window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c36-plumbing"] = window.COURSE_LANG["c36-plumbing"] || {};
window.COURSE_LANG["c36-plumbing"]["es"] = [
  {id:1, q:"¿Qué tubo de cobre para agua tiene la pared más gruesa y se prefiere para la acometida de agua enterrada?", opts:["Tipo M","Tipo L","Tipo K","Tipo DWV"], re:"El tipo K tiene la pared más gruesa de los tubos de agua comunes, por eso se usa enterrado y donde se necesita alta presión o protección mecánica."},
  {id:2, q:"¿Qué tubo plástico está listado para distribución de agua caliente y fría dentro de un edificio?", opts:["PVC","CPVC","ABS","Hierro fundido"], re:"El CPVC es PVC clorado formulado para soportar agua caliente; el PVC común no está clasificado para distribución de agua caliente."},
  {id:3, q:"El tubo negro de ABS en un edificio se usa más comúnmente para:", opts:["Tubería de desagüe, residuales y ventilación","Agua caliente a presión","Suministro de gas natural","Agua potable fría a presión"], re:"El ABS es un termoplástico negro muy usado para tubería DWV (desagüe, residuales y ventilación), no para agua a presión."},
  {id:4, q:"El tubo de cobre tipo L se usa más comúnmente para:", opts:["Líneas interiores de suministro de agua residenciales","Solo redes enterradas de servicio contra incendios","Solo tubería de desagüe y ventilación","Solo tubería de gas combustible"], re:"El tipo L tiene pared de grosor medio y es el tubo de cobre más común para la distribución interior de agua."},
  {id:5, q:"Comparado con los tipos K y L, el tubo de cobre tipo M tiene:", opts:["Una pared más gruesa que la K","Una pared idéntica a la K","La pared más delgada de los tres","Ningún uso para servicio de agua"], re:"El tipo M tiene la pared más delgada de los tres; algunas jurisdicciones limitan dónde puede usarse el tipo M para agua."},
  {id:6, q:"El tubo de acero galvanizado para agua ha caído en desuso porque, con el tiempo:", opts:["No se puede roscar","No puede conducir agua fría","Es demasiado flexible para sostenerse","Se corroe por dentro y restringe el flujo"], re:"El recubrimiento interior de zinc termina por desgastarse y el acero se oxida, estrechando el diámetro, restringiendo el flujo y causando fugas."},
  {id:7, q:"La tubería PEX se describe mejor como:", opts:["Un tubo metálico rígido","Un producto de drenaje de arcilla","Una tubería flexible de polietileno reticulado","Un conducto rígido de fibra de vidrio"], re:"El PEX es polietileno reticulado, una tubería plástica flexible usada para agua caliente y fría y unida con conexiones mecánicas."},
  {id:8, q:"El tubo de hierro fundido sin campana (no-hub) se usa principalmente para:", opts:["Agua potable a presión","Distribución de gas combustible","Líneas de aire comprimido","Tubería sanitaria de desagüe, residuales y ventilación"], re:"El hierro fundido no-hub es un material DWV por gravedad valorado por su resistencia y silencio, no para servicio a presión."},
  {id:9, q:"¿Qué material NO está aprobado para distribución de agua caliente potable?", opts:["Cobre tipo L","CPVC","PVC simple","PEX"], re:"El PVC simple está clasificado solo para agua fría y DWV; el cobre, el CPVC y el PEX sí están listados para agua caliente."},
  {id:10, q:"Una ventaja clave del tubo de drenaje de hierro fundido sobre el plástico DWV es que:", opts:["Amortigua el ruido del agua que fluye","Es más liviano de manejar","Cuesta menos","Nunca necesita soporte"], re:"La masa del hierro fundido amortigua el ruido del agua que circula por el tubo, una ventaja en edificios ocupados."},
  {id:11, q:"El tubo y las conexiones de latón usados en plomería son una aleación principalmente de:", opts:["Hierro y carbono","Plomo y antimonio","Aluminio y estaño","Cobre y zinc"], re:"El latón es principalmente cobre y zinc; el latón para agua potable también debe cumplir los límites de libre de plomo."},
  {id:12, q:"Para una acometida de agua enterrada de un edificio, lo más probable es que el instalador elija:", opts:["Cobre tipo M o tubo de pared delgada","Tubo ABS de DWV","Cobre tipo K u otro tubo aprobado con clasificación de presión","PVC de núcleo celular"], re:"La acometida enterrada requiere un material pesado, durable y con clasificación de presión, como el cobre tipo K u otro tubo de servicio de agua aprobado."},
  {id:13, q:"El tubo de PVC es adecuado para:", opts:["Aplicaciones de agua fría y DWV","Distribución de agua caliente a 180 F","Tubería de gas combustible","Líneas de vapor"], re:"El PVC está clasificado para agua fría y drenaje; se ablanda a temperaturas de agua caliente y no se usa para suministro caliente, gas ni vapor."},
  {id:14, q:"¿Qué tubería se instala comúnmente en rollos continuos largos para reducir el número de conexiones dentro de los muros?", opts:["Hierro fundido","Cobre rígido","PEX","Acero galvanizado"], re:"El PEX flexible puede correrse en rollos largos desde un colector hasta cada mueble, reduciendo conexiones ocultas y posibles puntos de fuga."},
  {id:15, q:"El tubo de cobre blando (recocido) se diferencia del cobre duro en que:", opts:["Siempre tiene la pared más delgada","Solo se usa para gas","No se puede soldar","Se puede doblar a mano y se vende en rollos"], re:"El cobre blando está recocido para poder doblarse y enrollarse; el cobre duro es rígido y se suministra en tramos rectos."},
  {id:16, q:"¿Cuál de estos es un tubo termoplástico de DWV y no un metal?", opts:["Hierro fundido no-hub","Acero galvanizado","ABS","Latón rojo"], re:"El ABS (acrilonitrilo butadieno estireno) es un tubo plástico negro de DWV; los demás son metales."},
  {id:17, q:"Una razón común para elegir cobre en lugar de plástico para tubería de agua es que el cobre:", opts:["Tolera temperaturas más altas y es rígido y durable","Es inmune a toda corrosión","Siempre es más barato","No necesita conexiones"], re:"El cobre soporta altas temperaturas, es rígido y duradero y está ampliamente aceptado, aunque cuesta más que el plástico."},
  {id:18, q:"\"Extra pesado\" y \"peso de servicio\" son clases de grosor de pared asociadas con:", opts:["Tubería PEX","Cobre blando","Tubo de CPVC","Tubo de hierro fundido para cloaca"], re:"El tubo de hierro fundido de campana y espiga se fabrica en clases de peso de servicio y extra pesado que difieren en grosor de pared."},
  {id:19, q:"¿Cuál afirmación sobre el tubo de DWV de ABS y PVC es correcta?", opts:["Ambos son metálicos","Ambos están clasificados para suministro de agua caliente","El ABS suele ser negro y el PVC suele ser blanco","Ninguno se puede usar para drenaje"], re:"El tubo de DWV de ABS suele ser negro y el de PVC suele ser blanco; ambos son materiales plásticos de drenaje, no de presión."},
  {id:20, q:"La clasificación de presión de un material de tubería generalmente disminuye cuando:", opts:["Su pared se hace más delgada","Su pared se hace más gruesa","Su longitud aumenta","Su color cambia"], re:"Para un diámetro y material dados, una pared más delgada soporta menos presión, por eso el cobre tipo M se clasifica por debajo del tipo K."},
  {id:21, q:"El tubo rígido de PVC y CPVC normalmente se une mediante:", opts:["Soldadura con fundente","Bandas no-hub","Anillos de engargolado","Cemento solvente (con imprimante en PVC/CPVC)"], re:"El PVC y el CPVC se sueldan químicamente con cemento solvente; el solvente ablanda y funde las superficies en una sola pieza."},
  {id:22, q:"El tubo de cobre para agua y sus conexiones se unen más comúnmente mediante:", opts:["Soldadura de solvente","Roscado del cobre blando","Soldadura blanda, también llamada sweating","Engargolado en frío con cinta"], re:"Las juntas de cobre se sueldan comúnmente (sweating) con fundente y soldadura sin plomo, atrayendo la soldadura fundida al casquillo por capilaridad."},
  {id:23, q:"La tubería de agua PEX se une comúnmente usando:", opts:["Cemento solvente","Juntas de plomo y estopa","Soldadura fuerte (brazing)","Conexiones de engargolado, expansión o a presión"], re:"El PEX es flexible y se une mecánicamente con anillos de engargolado, conexiones de expansión en frío o a presión, no con cemento ni soldadura."},
  {id:24, q:"El propósito del imprimante aplicado antes del cemento solvente de PVC es:", opts:["Solo dar color a la junta para inspección","Ablandar y limpiar la superficie para que el cemento la funda","Lubricar el tubo para el armado","Curar el cemento más rápido tras el armado"], re:"El imprimante ablanda y acondiciona la superficie de PVC/CPVC y elimina la contaminación para que el cemento solvente funda bien la junta."},
  {id:25, q:"El tubo de hierro fundido sin campana (no-hub) se une con:", opts:["Una junta de neopreno dentro de una abrazadera blindada de acero inoxidable","Plomo fundido y estopa","Cemento solvente","Una tuerca abocinada de latón"], re:"Las juntas no-hub usan una junta elastomérica (neopreno) alojada en un blindaje corrugado de acero inoxidable con bandas de abrazadera apretadas a un par determinado."},
  {id:26, q:"Una junta de cobre a presión (press-fit) se hace:", opts:["Calentando la conexión con soplete","Comprimiendo con una herramienta una conexión con anillo tórico interno sobre el tubo","Roscando el tubo en la conexión","Pegando el tubo con cemento solvente"], re:"Las conexiones a presión contienen un anillo tórico; una herramienta de prensado engarza la conexión sobre el tubo formando un sello mecánico hermético sin llama."},
  {id:27, q:"Una ventaja clave de seguridad de las conexiones a presión sobre la soldadura es que:", opts:["Requieren llama abierta","No necesitan llama, fundente ni soldadura","Solo se hacen en tubo seco","No se pueden inspeccionar"], re:"Las juntas a presión se hacen en frío con una herramienta, eliminando la llama abierta y el riesgo de trabajo en caliente de la soldadura."},
  {id:28, q:"Una junta abocinada en cobre blando se hace:", opts:["Expandiendo el extremo del tubo a un cono de 45 grados sujeto por una tuerca de abocinado","Fundiendo soldadura en el casquillo","Cementando el tubo en un casquillo","Engargolando un anillo sobre una espiga"], re:"El extremo del tubo de cobre blando se abocina a un cono de 45 grados y se aprieta contra el asiento con una tuerca, método usado para gas combustible y conexiones similares."},
  {id:29, q:"Al unir dos plásticos de drenaje distintos como ABS y PVC, el método recomendado es:", opts:["Encintar la junta","Calentar ambos extremos y presionarlos","Roscar los plásticos entre sí","Usar un cople de transición aprobado o cemento de transición"], re:"Los plásticos distintos deben unirse con un cople de transición aprobado (o cemento de transición listado) en lugar de mezclar sus cementos individuales."},
  {id:30, q:"Las juntas de plomo y estopa (calafateadas) se asocian con:", opts:["Tubería PEX","Tubo de hierro fundido de campana y espiga para cloaca","Tubo de CPVC","Líneas de gas de cobre blando"], re:"La junta tradicional de campana y espiga del hierro fundido empaca estopa en la campana y luego vierte plomo fundido encima; las juntas con junta de hule la han reemplazado."},
  {id:31, q:"El fundente de soldadura se aplica a una junta de cobre principalmente para:", opts:["Aumentar la presión del agua","Limpiar el metal y ayudar a que la soldadura fluya a la junta","Dar color a la conexión","Frenar la soldadura"], re:"El fundente elimina los óxidos y permite que la soldadura fundida moje y fluya a la junta por capilaridad para un sello firme."},
  {id:32, q:"Las juntas roscadas de tubo de acero o latón se sellan con:", opts:["Cemento solvente","Pasta para juntas o cinta de PTFE en las roscas","Un manguito de junta de neopreno","Una prensa de anillo tórico"], re:"Las roscas cónicas (NPT) se sellan con pasta para juntas (pipe dope) o cinta de PTFE que llena la espiral de la rosca y evita fugas."},
  {id:33, q:"Una conexión a presión por inserción (push-fit) sujeta el tubo con:", opts:["Cemento solvente dentro del casquillo","Dientes internos de agarre y un sello de anillo tórico","Un collar de plomo vertido","Un cordón soldado"], re:"Las conexiones push-fit usan dientes de acero inoxidable para sujetar el tubo y un anillo tórico para sellarlo, permitiendo una conexión sin herramienta en cobre, CPVC o PEX."},
  {id:34, q:"Las conexiones PEX de expansión en frío funcionan:", opts:["Fundiendo el tubo a la conexión","Expandiendo el tubo y el anillo y dejando que encojan sobre la conexión","Pegando el tubo en un casquillo","Calafateando la junta con plomo"], re:"Con la expansión en frío (p. ej., PEX-A) se estiran el tubo y un anillo de expansión, se inserta la conexión y la memoria del material los contrae apretados a su alrededor."},
  {id:35, q:"¿Por qué se debe dar a las juntas cementadas de PVC el tiempo adecuado de fraguado y curado antes de presurizar?", opts:["Para que el imprimante seque a un color","Para que el solvente desarrolle toda la resistencia de la junta","Para que el tubo se enfríe de la soldadura","Para que las roscas asienten"], re:"Las soldaduras con solvente necesitan tiempo de fraguado y curado para que la unión fundida alcance toda su resistencia antes de presurizar la línea; apresurarse puede causar fallas."},
  {id:36, q:"En una junta de cobre soldada, la acción capilar se refiere a:", opts:["La presión del agua empujando la soldadura hacia afuera","La soldadura fundida atraída al espacio entre tubo y conexión","El tamaño de la llama del soplete","El fundente convirtiéndose en ceniza"], re:"Una holgura de junta correctamente dimensionada permite que la acción capilar atraiga la soldadura fundida alrededor de todo el casquillo para un sello completo."},
  {id:37, q:"¿Qué método de unión se realiza en una línea de cobre mojada o sin drenar, sin vaciarla primero?", opts:["Soldadura blanda","Soldadura fuerte (brazing)","Conexión a presión","Roscado"], re:"Las conexiones a presión pueden hacerse en líneas que no están totalmente drenadas, a diferencia de la soldadura, que requiere que la zona de la junta esté seca."},
  {id:38, q:"Las abrazaderas de acero inoxidable de un cople no-hub se aprietan a:", opts:["Solo a mano sin herramienta","Un valor de par especificado con una llave calibrada","Hasta que el blindaje se deforme por completo","Ningún valor en particular"], re:"Las bandas se aprietan a un par especificado por el fabricante (comúnmente 60 libras-pulgada) para que la junta selle sin apretar de más ni de menos."},
  {id:39, q:"La soldadura fuerte (brazing) se diferencia de la soldadura blanda en que el brazing:", opts:["Usa un metal de aporte de menor temperatura","Usa un metal de aporte de mayor temperatura para juntas más fuertes","No requiere calor","Usa cemento solvente"], re:"El brazing usa temperaturas más altas y metales de aporte que funden por encima de unos 840 F, produciendo juntas más fuertes que la soldadura blanda."},
  {id:40, q:"Antes de soldar, el extremo del tubo de cobre y el casquillo de la conexión deben estar:", opts:["Cubiertos de pintura","Limpios y brillantes con tela de esmeril o un cepillo de conexiones","Remojados en imprimante","Calentados hasta ponerse rojos"], re:"Limpiar las superficies de contacto hasta el metal brillante elimina el óxido para que el fundente y la soldadura se adhieran bien y la junta no fugue."},
  {id:41, q:"Una unión (union) se instala en un tramo de tubería principalmente para:", opts:["Reducir el diámetro del tubo","Permitir desconectar el tubo sin cortarlo","Cambiar la dirección del flujo 90 grados","Ventilar aire atrapado"], re:"Una unión permite desarmar y rearmar un tramo de tubo para dar servicio sin cortar, desenroscando su anillo central."},
  {id:42, q:"Una unión dieléctrica se usa para:", opts:["Acelerar el flujo de agua","Separar metales distintos para evitar la corrosión galvánica","Reducir la presión del agua","Agregar un registro de limpieza"], re:"Una unión dieléctrica aísla eléctricamente el cobre del acero o el galvanizado para que la corrosión galvánica no consuma la junta."},
  {id:43, q:"En tubería DWV, una conexión en Y (wye) se prefiere sobre una tee sanitaria en tramos horizontales porque:", opts:["Es más barata de comprar","Une la derivación a unos 45 grados para un flujo suave","Tiene una abertura más grande","No necesita soporte"], re:"Una Y mete la derivación a unos 45 grados, manteniendo el residuo en movimiento para que los sólidos no se asienten, lo que una tee aguda causaría en una línea horizontal."},
  {id:44, q:"Un cople reductor se usa para:", opts:["Unir dos tubos de diferente diámetro","Cambiar la dirección del flujo","Tapar el extremo de una línea","Agregar una llave de paso"], re:"Un cople reductor conecta un tubo más grande con uno más pequeño en un tramo recto, haciendo la transición entre los dos tamaños."},
  {id:45, q:"Un codo (ell) se usa para:", opts:["Unir tres tubos","Cambiar la dirección de un tramo de tubo","Reducir la presión","Proporcionar un registro de limpieza"], re:"Los codos cambian la dirección del tubo, comúnmente 90 o 45 grados; los codos de barrido largo dan un giro más suave para el drenaje."},
  {id:46, q:"Una conexión tee (T) se usa para:", opts:["Tapar una línea","Crear una derivación desde un tramo principal","Unir dos tubos iguales en línea recta","Desarmar un tramo para servicio"], re:"Una tee proporciona una derivación a 90 grados del principal; una tee sanitaria tiene un barrido curvo para el flujo de drenaje."},
  {id:47, q:"Un buje (bushing) es una conexión que se usa para:", opts:["Adaptar la abertura de una conexión grande a un tubo más pequeño","Cambiar la dirección 45 grados","Conectar dos tubos no-hub","Proporcionar una abertura de alivio"], re:"Un buje se rosca o encaja en una abertura más grande para reducirla a un tamaño menor, ocupando menos espacio que un cople reductor."},
  {id:48, q:"Una combinación de Y y octavo de vuelta se usa en el drenaje para:", opts:["Hacer una derivación aguda de 90 grados en una columna vertical","Crear un cambio de dirección de barrido largo para el flujo de la derivación","Tapar una ventilación","Reducir dos tamaños a la vez"], re:"Combinar una Y de 45 grados con un octavo de vuelta forma un giro largo y barrido que permite que una derivación entre sin estrangular el flujo."},
  {id:49, q:"Un cople (cople recto) se usa para:", opts:["Unir dos tubos del mismo tamaño extremo con extremo","Derivar una línea","Cambiar la dirección","Reducir la presión"], re:"Un cople recto conecta dos tubos del mismo diámetro en línea; un cople deslizante o de reparación puede deslizarse encima para reparar un tramo cortado."},
  {id:50, q:"¿Qué conexión cierra permanentemente el extremo de un tubo roscado?", opts:["Un casquete (cap)","Una unión","Una Y","Un cople"], re:"Un casquete se enrosca sobre el exterior de un extremo macho para cerrarlo; un tapón cierra una abertura hembra roscada desde adentro."},
  {id:51, q:"En un desagüe horizontal, un registro de limpieza se instala mejor usando una:", opts:["Tee sanitaria acostada","Y (o Y combinada) para que la varilla pase con el flujo","Codo simple de 90 grados","Cople recto simple"], re:"Una Y permite que la varilla de limpieza siga la dirección del flujo, por eso los códigos exigen una Y y no una tee sanitaria para un registro horizontal."},
  {id:52, q:"Un codo de barrido largo (radio largo) se prefiere en el drenaje porque:", opts:["Gira el flujo más gradualmente para mantener el residuo en movimiento","Ahorra espacio frente a un codo corto","Solo se requiere para ventilación","Reduce el tamaño del tubo"], re:"Un codo de barrido largo tiene un radio mayor que gira el residuo gradualmente, reduciendo la posibilidad de tapones frente a un codo de radio corto."},
  {id:53, q:"Una conexión tipo street (codo street, por ejemplo) tiene:", opts:["Dos extremos hembra","Un extremo macho y uno hembra","Tres aberturas","Una válvula incorporada"], re:"Una conexión street tiene un extremo macho (espiga) y uno hembra (campana), por lo que se une directo a otra conexión sin un niple corto."},
  {id:54, q:"Cuando un tubo de cobre debe conectarse a un tubo de acero galvanizado, la conexión preferida por el código es una:", opts:["Cople de latón simple","Unión dieléctrica o conexión dieléctrica","Casquillo de cemento solvente","Junta abocinada"], re:"Una conexión dieléctrica separa los metales distintos, evitando la corrosión galvánica que de otro modo atacaría la conexión de cobre a acero."},
  {id:55, q:"Un adaptador de sifón (trap adapter) se usa para:", opts:["Conectar el sifón tubular de un mueble al tubo de desagüe","Reducir la presión del agua","Ventilar la columna","Unir dos campanas de hierro fundido"], re:"Un adaptador de sifón hace la transición del sifón tubular de pared delgada del mueble al tubo de desagüe DWV estándar con tuerca deslizante y arandela."},
  {id:56, q:"Una brida de inodoro (closet flange) sirve para:", opts:["Regular la presión del tanque","Anclar el inodoro y conectarlo al desagüe","Ventilar el baño","Reducir el tamaño del desagüe"], re:"La brida de inodoro se fija al piso y al tubo de desagüe, proporcionando la superficie de sello y el anclaje de pernos para el inodoro."},
  {id:57, q:"¿Por qué se debe mantener razonable el número de conexiones en una línea de agua?", opts:["Las conexiones solo agregan costo","Cada conexión añade pérdida por fricción y un posible punto de fuga","Las conexiones reducen la resistencia del tubo a cero","Las conexiones nunca están aprobadas por el código"], re:"Cada conexión añade fricción (pérdida de presión) y otra junta que podría fugar, por eso los tramos se planean usando solo las conexiones necesarias."},
  {id:58, q:"Un reductor en una línea de desagüe horizontal suele instalarse como reductor excéntrico para:", opts:["Mantener nivelada la parte superior para que los sólidos no se estanquen","Aumentar bruscamente la pendiente","Agregar una ventilación","Permitir el roscado"], re:"Un reductor excéntrico mantiene un lado (la base) alineado para que el desagüe horizontal no forme una bolsa donde se acumulen sólidos y agua."},
  {id:59, q:"Un cople no-hub se diferencia de una unión roscada en que:", opts:["Sella eléctricamente metales distintos","Une hierro fundido sin campana con una banda de abrazadera con junta","Solo se usa en PEX","Requiere cemento solvente"], re:"Un cople no-hub sujeta una junta sobre los extremos de tubo de hierro fundido sin campana, mientras que una unión es una junta roscada desarmable para tubo metálico."},
  {id:60, q:"Un tapón (plug) se usa para:", opts:["Cerrar una abertura hembra roscada","Cerrar un extremo macho de tubo","Derivar una línea a 45 grados","Reducir dos tamaños de tubo"], re:"Un tapón se enrosca en una abertura o conexión hembra roscada para cerrarla, mientras que un casquete encaja sobre un extremo macho."},
  {id:61, q:"Una válvula de compuerta es más adecuada para servicio que está:", opts:["Estrangulando el flujo con frecuencia","Totalmente abierto o totalmente cerrado (aislamiento)","Solo previniendo el retorno","Reduciendo la presión del sistema"], re:"Una válvula de compuerta levanta una cuña fuera del paso al abrir y es para corte total, no para estrangular, donde puede vibrar y erosionarse."},
  {id:62, q:"Una válvula de globo está diseñada principalmente para:", opts:["Estrangular y regular el flujo","Proporcionar un corte de un cuarto de vuelta","Prevenir el flujo inverso","Aliviar la presión excesiva"], re:"Una válvula de globo obliga al flujo a pasar por un asiento en trayectoria en Z, dando buen control de estrangulación a costa de una caída de presión mayor que la compuerta o la bola."},
  {id:63, q:"Una válvula de bola se opera mediante:", opts:["Muchas vueltas de un volante","Un cuarto de vuelta (90 grados) de la manija","Un flotador","Expansión térmica"], re:"Una válvula de bola usa una bola perforada que abre o cierra con un cuarto de vuelta, dando un corte rápido y confiable con baja caída de presión."},
  {id:64, q:"Una válvula de retención (check) se instala para:", opts:["Estrangular el flujo","Permitir el flujo en una dirección y prevenir el flujo inverso","Reducir la presión a 80 psi","Filtrar residuos"], re:"Una válvula de retención permite el flujo en un sentido y cierra contra el flujo inverso, ayudando a prevenir el retorno y proteger equipos como las bombas."},
  {id:65, q:"Una válvula reductora de presión (PRV) en una acometida de agua se usa para:", opts:["Aumentar la presión de entrada baja","Bajar la presión de entrada alta a un valor seguro","Prevenir el retorno","Drenar el sistema"], re:"Una PRV reduce automáticamente la alta presión de la calle a un valor menor (comúnmente 80 psi o menos) para proteger la tubería y los muebles del edificio."},
  {id:66, q:"Una llave de paso angular (stop de mueble) se instala para:", opts:["Cortar el agua a un solo mueble para darle servicio","Reducir la presión de toda la casa","Prevenir el golpe de ariete en todas partes","Ventilar el desagüe del mueble"], re:"Una llave angular permite aislar un solo mueble, como una llave o un inodoro, para repararlo sin cortar el agua de todo el edificio."},
  {id:67, q:"¿Por qué una válvula de compuerta es mala opción para estrangular el flujo?", opts:["No puede cerrar del todo","La apertura parcial causa vibración y erosión del asiento","No tiene manija","Solo encaja en tubo plástico"], re:"Mantenida medio abierta, el disco de la compuerta vibra en el flujo y el asiento se erosiona, por eso las compuertas se usan totalmente abiertas o cerradas."},
  {id:68, q:"Una llave de paso angular residencial típica tiene una salida de:", opts:["3/8 de pulgada de compresión","2 pulgadas roscada","Campana de 4 pulgadas","Solo soldadura de 1 pulgada"], re:"La mayoría de las llaves angulares de mueble tienen una salida de compresión de 3/8 de pulgada que conecta al tubo de alimentación de la llave o el inodoro."},
  {id:69, q:"Una llave de manguera (sillcock) que suministra a una manguera de jardín debe llevar:", opts:["Un regulador de presión","Un segundo check en el medidor","Un rompevacío para conexión de manguera","Una manija más grande"], re:"Un rompevacío para conexión de manguera evita que el agua contaminada sea succionada de regreso por la manguera hacia el suministro potable."},
  {id:70, q:"En una válvula de retención de columpio (swing check), el elemento de cierre es un:", opts:["Cuña deslizante","Disco abisagrado que se cierra de golpe contra el flujo inverso","Bola giratoria","Diafragma empujado solo por un resorte"], re:"Una check de columpio tiene un disco abisagrado que abre con el flujo directo y se cierra de golpe cuando el flujo se invierte."},
  {id:71, q:"La válvula de corte principal en la acometida de agua de un edificio existe principalmente para:", opts:["Reducir la presión","Aislar el agua de todo el edificio para reparaciones o emergencias","Calentar el agua","Ventilar el sistema"], re:"Una válvula principal de apertura total permite cortar el suministro de todo el edificio para mantenimiento o en una emergencia como un tubo reventado."},
  {id:72, q:"Comparada con una válvula de compuerta, una válvula de bola generalmente ofrece:", opts:["Operación más lenta","Operación de corte más rápida y sello confiable tras largos periodos inactiva","Mejor estrangulación fina","Ninguna clasificación de presión"], re:"Las válvulas de bola cierran en un cuarto de vuelta y tienden a sellar de forma confiable incluso tras estar sin uso, por eso se usan mucho para corte."},
  {id:73, q:"Cuando una válvula reductora de presión crea un sistema cerrado, la instalación también necesita:", opts:["Un segundo medidor","Un tanque de expansión térmica","Un drenaje más grande","Ningún dispositivo adicional"], re:"Tras una PRV (o un check), el agua no puede expandirse de regreso a la red, así que se agrega un tanque de expansión térmica para absorber el aumento de presión por calentamiento."},
  {id:74, q:"Un amortiguador de golpe de ariete es un dispositivo que:", opts:["Aumenta la presión estática","Amortigua el choque cuando una válvula de cierre rápido detiene el flujo","Filtra sedimento","Previene el congelamiento"], re:"Un amortiguador contiene una cámara de aire o pistón que absorbe la sobrepresión creada cuando una válvula de cierre rápido detiene de golpe el agua, reduciendo el golpeteo."},
  {id:75, q:"¿Qué tipo de válvula tiene la menor caída de presión cuando está totalmente abierta?", opts:["Válvula de globo","Válvula de compuerta o de bola de paso completo","Válvula de globo angular","Válvula de pie"], re:"Una válvula de compuerta o de bola de paso completo totalmente abierta deja un paso casi libre, dando muy poca resistencia frente a la trayectoria en Z de un globo."},
  {id:76, q:"Una válvula de alivio en un sistema de agua cerrado se diferencia de una válvula de corte en que:", opts:["Se opera a mano","Abre automáticamente para aliviar la presión excesiva","Estrangula el flujo continuamente","Solo detiene el flujo inverso"], re:"Una válvula de alivio es de resorte y abre por sí sola cuando la presión (o la temperatura) supera un límite, protegiendo al sistema de una ruptura."},
  {id:77, q:"Una válvula de pie (foot valve) al fondo de la línea de succión de una bomba es un tipo de:", opts:["Regulador de presión","Válvula de retención que mantiene cebada la línea","Válvula de compuerta","Válvula de globo"], re:"Una válvula de pie es una check con filtro que retiene agua (cebado) en la línea de succión para que la bomba no pierda el cebado."},
  {id:78, q:"En una llave, los stops de suministro caliente y frío se disponen por convención de modo que, de frente al mueble:", opts:["El caliente a la izquierda y el frío a la derecha","Ambos a la derecha","El caliente a la derecha y el frío a la izquierda","La posición no importa"], re:"Por convención de larga data, el caliente va a la izquierda y el frío a la derecha en el mueble, coincidiendo con lo que espera el usuario."},
  {id:79, q:"Una llave de paso angular de un cuarto de vuelta normalmente se construye como una:", opts:["Llave de globo de varias vueltas","Válvula tipo bola","Válvula de diafragma","Válvula de compuerta"], re:"Las llaves angulares modernas de un cuarto de vuelta usan una pequeña válvula de bola, más rápida y que tiende a agarrotarse menos que los viejos stops de compresión de varias vueltas."},
  {id:80, q:"La razón principal de instalar stops individuales en cada mueble de un edificio es:", opts:["Aumentar la presión general","Permitir dar servicio a cada mueble sin cortar el agua de todo el edificio","Eliminar la necesidad de una válvula principal","Reducir el tamaño del tubo"], re:"Los stops de mueble permiten aislar una sola llave, inodoro o aparato para repararlo mientras el resto del edificio conserva el servicio de agua."},
  {id:81, q:"El tubo de DWV de PVC y ABS Cédula 40 horizontal comúnmente debe soportarse a intervalos de aproximadamente:", opts:["4 pies","12 pies","20 pies","No se requiere soporte"], re:"El tubo plástico de DWV se pandea entre soportes, así que los códigos comúnmente exigen soporte horizontal cada 4 pies aproximadamente para cualquier diámetro."},
  {id:82, q:"Un soporte o abrazadera de tubo debe ser de un material que:", opts:["Sea siempre de acero sin importar el tubo","Sea compatible con el tubo para evitar la corrosión","Sea lo más pequeño posible","Conduzca bien la electricidad"], re:"Los soportes deben ser compatibles con el tubo (por ejemplo, no acero desnudo directo sobre cobre) para que no haya una reacción galvánica o química que corroa el tubo."},
  {id:83, q:"El aislamiento de tubería en una línea de agua caliente sirve principalmente para:", opts:["Aumentar la presión del agua","Reducir la pérdida de calor y ahorrar energía","Agregar soporte estructural","Prevenir el retorno"], re:"Aislar el tubo de agua caliente reduce la pérdida de calor, así el agua llega más caliente y el calentador usa menos energía."},
  {id:84, q:"Aislar un tubo de agua fría en una zona húmeda ayuda principalmente a:", opts:["Aumentar el caudal","Controlar la condensación (sudoración) en el tubo","Subir la temperatura del agua","Aumentar la presión"], re:"Las superficies de tubo frío por debajo del punto de rocío sudan; el aislamiento de celda cerrada con barrera de vapor evita que la humedad se condense y gotee."},
  {id:85, q:"El aislamiento de tubería se usa en zonas sin calefacción principalmente para:", opts:["Acelerar el drenaje","Frenar la pérdida de calor y reducir el riesgo de congelamiento","Agregar código de color","Reemplazar los soportes de tubo"], re:"El aislamiento no garantiza que un tubo no se congele, pero frena la pérdida de calor y alarga el tiempo antes de que el agua estancada se congele y reviente el tubo."},
  {id:86, q:"Donde un tubo de cobre desnudo descansaría sobre un soporte de acero, la buena práctica es:", opts:["Unirlos eléctricamente","Aislar el cobre del acero con un soporte compatible o recubierto","Soldarlos entre sí","Dejar el cobre sin soporte"], re:"Separar el cobre de soportes de metal distinto con un soporte recubierto de plástico o compatible con cobre evita la corrosión galvánica en el punto de contacto."},
  {id:87, q:"El tubo de hierro fundido sin campana horizontal generalmente se soporta:", opts:["Solo en los extremos del edificio","En o cerca de cada junta (y dentro de un espaciamiento limitado)","Cada 20 pies","Nunca, porque es rígido"], re:"El pesado hierro fundido y sus juntas con junta de hule se soportan en o cerca de cada campana/junta y dentro de un espaciamiento limitado para que las juntas no se esfuercen."},
  {id:88, q:"Comparado con el tubo metálico rígido, el tubo plástico generalmente necesita:", opts:["Espaciamiento de soporte más amplio","Espaciamiento de soporte más cerrado por ser más flexible","Ningún soporte","Soporte solo cuando es vertical"], re:"El tubo plástico es más flexible y se pandea más, así que requiere espaciamiento de soporte más cerrado que el mismo tamaño de tubo metálico rígido."},
  {id:89, q:"La tubería vertical en un tramo de varios pisos típicamente se soporta:", opts:["Solo en la parte más alta","En cada piso o dentro de un intervalo vertical limitado","Nunca","Solo en la base"], re:"El tubo vertical se soporta en las líneas de piso o dentro de un intervalo del código (comúnmente no más de unos 10 pies) para que su peso se cargue por tramos, no todo abajo."},
  {id:90, q:"La tubería flexible PEX corrida horizontalmente generalmente necesita soporte:", opts:["A mayor espaciamiento que el cobre rígido","A menor espaciamiento que el cobre rígido por ser flexible","Solo en el colector","Nunca"], re:"Como el PEX es flexible y se pandea con facilidad, se soporta a intervalos más cercanos que el cobre rígido (a menudo cerca de 32 pulgadas en horizontal)."},
  {id:91, q:"La función principal de un soporte de tubo es:", opts:["Reducir la presión del agua","Cargar el peso del tubo y su contenido y mantener la pendiente correcta","Prevenir el retorno","Aislar el tubo"], re:"Los soportes sostienen el tubo y su agua para que no se pandee, manteniendo el tubo de drenaje en su pendiente requerida y evitando esfuerzos en las juntas."},
  {id:92, q:"La espuma elastomérica de celda cerrada es un aislamiento de tubería popular porque:", opts:["Conduce bien el calor","Resiste la humedad y sirve en líneas calientes y frías","Es un soporte estructural","Solo encaja en hierro fundido"], re:"La espuma de celda cerrada resiste la absorción de agua, lo que la hace adecuada para líneas frías (control de condensación) y calientes (retención de calor) por igual."},
  {id:93, q:"Donde un tubo de drenaje plástico pasa por un montante metálico o una abrazadera, el instalador debe:", opts:["Apretarlo de modo que no pueda moverse en absoluto","Dejar espacio para la expansión y proteger el tubo de la abrasión","Soldar el punto de contacto","Quitar el soporte"], re:"El tubo plástico se expande y contrae con la temperatura, así que los soportes deben dejarlo moverse y protegerlo del roce en los bordes metálicos."},
  {id:94, q:"El soporte adecuado de una línea de desagüe horizontal es importante principalmente porque el pandeo puede:", opts:["Aumentar la presión del agua","Crear puntos bajos (panzas) donde se acumula el residuo","Mejorar la ventilación","Reducir el tamaño del tubo"], re:"Un pandeo forma una panza que retiene agua y sólidos, provocando tapones, por eso los desagües deben soportarse para conservar una pendiente continua."},
  {id:95, q:"Aislar tanto los tubos calientes como los fríos en un muro también puede ayudar a:", opts:["Aumentar el golpe de ariete","Reducir el ruido del agua que fluye en los tubos","Subir la presión estática","Eliminar la necesidad de válvulas"], re:"Además del beneficio térmico, el aislamiento de tubería puede amortiguar el sonido del agua que fluye y reducir el ruido transmitido por la estructura."},
  {id:96, q:"El tipo de tubo de cobre para agua se identifica en obra por una franja de color; el tipo K se marca:", opts:["Rojo","Azul","Verde","Amarillo"], re:"Por el código de color estándar, el tipo K es verde, el tipo L es azul y el tipo M es rojo, impreso a lo largo del tubo."},
  {id:97, q:"¿Qué color de identificación lleva el tubo de cobre tipo L?", opts:["Azul","Verde","Rojo","Negro"], re:"El tipo L se identifica con azul; el tipo K es verde y el tipo M es rojo bajo el sistema común de marcado de tubo de cobre."},
  {id:98, q:"Todo el tubo, la soldadura y las conexiones de un sistema de agua potable deben ser:", opts:["Pintados de azul","De al menos 2 pulgadas de tamaño","Solo galvanizados","Libres de plomo"], re:"Los materiales en contacto con agua potable deben cumplir los límites de libre de plomo para proteger la calidad del agua, requisito reforzado por la ley federal y de California."},
  {id:99, q:"La tubería PEX vendida en colores rojo y azul usa esos colores para:", opts:["Indicar diferentes clasificaciones de presión","Identificar líneas calientes frente a frías para el instalador","Mostrar cuál es para gas","Marcar paredes más gruesas"], re:"El color del PEX (rojo para caliente, azul para frío, blanco para cualquiera) es solo para identificación; el color no cambia la clasificación de presión ni de temperatura de la tubería."},
  {id:100, q:"Una junta de neopreno usada en un cople de hierro fundido no-hub debe cumplir:", opts:["Una norma de pureza de soldadura","Una norma de elastómero como ASTM C564","Una norma de temple del cobre","Una norma de cemento solvente"], re:"La junta de neopreno para las juntas de hierro fundido sin campana se especifica según ASTM C564, asegurando que selle y resista los materiales del sistema de drenaje."},
  {id:101, q:"La tubería de acometida de agua se define mejor como la tubería que va desde:", opts:["La red pública o fuente hasta el sistema de distribución de agua del edificio","El medidor de agua hasta el mueble más lejano","El calentador de agua hasta cada mueble","De mueble a mueble dentro de una pared"], re:"La acometida es el tubo entre la red pública (u otra fuente) y el punto donde comienza el sistema de distribución del edificio, normalmente en la estructura o justo dentro de ella."},
  {id:102, q:"Una válvula de apertura total exigida para un medidor de agua debe tener un área de paso que sea:", opts:["La mitad del área de la acometida","Al menos igual a la sección de la acometida de agua","El doble del área de la acometida","Menor que la acometida para estrangular el flujo"], re:"La válvula del medidor debe ser de tipo full-way (paso total) cuya área abierta sea al menos la de la acometida para no restringir el flujo."},
  {id:103, q:"La cubierta de tierra mínima normalmente exigida sobre un tubo de acometida de agua enterrado es de aproximadamente:", opts:["3 pulgadas","6 pulgadas","12 pulgadas","36 pulgadas"], re:"Los códigos generalmente exigen al menos 12 pulgadas de relleno sobre la parte superior del tubo de acometida enterrado para protegerlo."},
  {id:104, q:"Cuando el albañal del edificio no es de material aprobado para presión, el tubo de acometida de agua debe separarse de él horizontalmente no menos de:", opts:["1 pie","2 pies","20 pies","5 pies"], re:"Una acometida de agua debe estar al menos a 5 pies de tierra no alterada o compactada de un albañal común para reducir el riesgo de contaminación."},
  {id:105, q:"Una acometida de agua puede ir a menos de 5 pies de un albañal solo si el tubo de agua se coloca:", opts:["Al menos 12 pulgadas por encima de la parte superior del albañal","Debajo del albañal","En la misma zanja al mismo nivel","Hecho de hierro fundido"], re:"La separación de 5 pies puede reducirse cuando el fondo de la acometida de agua queda al menos 12 pulgadas por encima del punto más alto del albañal."},
  {id:106, q:"Cuando un tubo de acometida de agua debe cruzar un albañal del edificio, el tubo de agua debe:", opts:["Dejarse desnudo y tocando el albañal","Enfundarse o mantener sus juntas bien alejadas del cruce","Reducirse un tamaño de tubo","Amarrarse al albañal como apoyo"], re:"En un cruce, la acometida de agua se enfunda comúnmente o se mantienen sus juntas lejos del albañal para que una fuga no aspire contaminación."},
  {id:107, q:"Una válvula de drenaje (purga) en el lado de descarga de la válvula de un medidor interior se coloca principalmente para:", opts:["Aumentar la presión","Calentar el medidor","Permitir drenar la tubería aguas abajo","Ventilar gas"], re:"Una válvula de drenaje aguas abajo del medidor permite vaciar la tubería del edificio para reparaciones o protección contra congelamiento."},
  {id:108, q:"La válvula principal de cierre (control) del edificio normalmente se ubica:", opts:["En el mueble más lejano","En el techo","Dentro del calentador de agua","Cerca de donde la acometida entra al edificio o en el medidor, fácilmente accesible"], re:"Una válvula de control de apertura total fácilmente accesible se instala cerca del medidor o donde entra la acometida, para poder cerrar todo el edificio."},
  {id:109, q:"Un medidor de agua sirve principalmente para:", opts:["Medir el volumen de agua usada","Reducir la presión del agua","Prevenir el retorno","Filtrar sedimento"], re:"El medidor registra la cantidad de agua que pasa al edificio para la facturación; no es un dispositivo de presión ni antirretorno."},
  {id:110, q:"Las uniones en la entrada y salida de un medidor de agua se colocan para que el medidor pueda:", opts:["Presurizarse más","Retirarse o reemplazarse sin cortar el tubo","Usarse como válvula de cierre","Enterrarse más profundo"], re:"Las uniones permiten quitar y reinstalar el medidor para servicio o cambio sin cortar la tubería."},
  {id:111, q:"Una acometida de agua demasiado pequeña para la demanda del edificio probablemente causará:", opts:["Exceso de presión","Solo golpe de ariete","Flujo inadecuado y caída de presión en los muebles","Retorno"], re:"Una acometida subdimensionada no puede conducir el flujo requerido, por lo que la presión cae y los muebles se quedan sin agua cuando la demanda es alta."},
  {id:112, q:"Las dos cantidades principales necesarias para dimensionar un tubo de acometida de agua son la presión disponible y:", opts:["El color del tubo","Solo el número de pisos","El costo del cobre","El flujo (demanda) requerido que el edificio debe entregar"], re:"El dimensionamiento equilibra la demanda (flujo necesario) con la presión disponible y la pérdida por fricción que impondrá el tubo."},
  {id:113, q:"El tubo de acometida de agua de acero galvanizado hoy generalmente se desaconseja principalmente porque:", opts:["Se corroe y restringe el flujo con acumulación mineral con el tiempo","Es demasiado flexible","No se puede roscar","Es ilegal en todas partes"], re:"El tubo galvanizado se oxida por dentro y se obstruye con sarro, reduciendo el flujo; suelen preferirse cobre, PEX o plástico."},
  {id:114, q:"Antes de dimensionar el suministro del edificio, el plomero debe determinar primero:", opts:["El esquema de pintura","La presión estática (sin flujo) disponible en la acometida","El número de registros de limpieza","La profundidad del sello del sifón"], re:"La presión estática disponible en la fuente es el punto de partida; de ella el diseñador resta las pérdidas por elevación y fricción."},
  {id:115, q:"Un manómetro conectado en una llave de manguera sin agua fluyendo indica la presión del sistema de tipo:", opts:["Residual","Velocidad de flujo","Estática","Pérdida por fricción"], re:"Sin muebles abiertos, el manómetro muestra la presión estática; cuando el agua fluye, la lectura más baja es la presión residual."},
  {id:116, q:"El sistema de distribución de agua dentro de un edificio comienza:", opts:["En el embalse de la ciudad","En cada llave","En la salida del calentador de agua","Donde termina la acometida de agua, normalmente en el medidor o la válvula principal"], re:"La tubería de distribución es la red aguas abajo de la acometida que lleva agua a muebles y aparatos por todo el edificio."},
  {id:117, q:"Una llave de toma (corporation stop) y una llave de banqueta (curb stop) son válvulas asociadas con:", opts:["La conexión de la acometida a la red pública y en el límite de propiedad","El calentador de agua","El sistema de ventilación","El brazo del sifón"], re:"La llave de toma perfora la red y la llave de banqueta queda cerca del límite de propiedad, ambas en la acometida antes del medidor."},
  {id:118, q:"Cuando la presión estática del agua en la tubería de suministro supera 80 psi, el código exige:", opts:["Un medidor más grande","Un regulador de presión aprobado para reducirla a 80 psi o menos","Una segunda acometida de agua","Ninguna acción por debajo de 100 psi"], re:"Por encima de 80 psi estáticos, una válvula reductora aprobada precedida de un filtro debe bajar la presión a 80 psi o menos."},
  {id:119, q:"Una válvula reductora de presión (PRV) en una acometida de agua normalmente va precedida de:", opts:["Solo una válvula de retención","Una segunda PRV","Un filtro adecuado","Un rompevacío"], re:"Un filtro adecuado antes del regulador evita que los residuos ensucien el asiento de la válvula, aunque los reguladores más grandes pueden estar exentos de un filtro separado."},
  {id:120, q:"Los reguladores de presión para un sistema de distribución de agua potable deben cumplir con:", opts:["ASSE 1010","NSF para drenajes","Ninguna norma","ASSE 1003 (o AWWA C530)"], re:"Los reguladores de presión para agua potable deben cumplir ASSE 1003 o AWWA C530 para funcionar de forma confiable y segura."},
  {id:121, q:"Instalar una PRV normalmente convierte la tubería del edificio en un:", opts:["Sistema cerrado en el que la expansión térmica puede elevar la presión","Sistema abierto ventilado","Drenaje por gravedad","Sistema de bajo peligro que no necesita alivio"], re:"Una PRV actúa como restricción de un solo sentido, por lo que el agua caliente expandida no puede regresar a la red y se necesita un dispositivo de control de expansión."},
  {id:122, q:"Una razón común para limitar la presión del agua del edificio a unos 80 psi es que una presión mayor:", opts:["Ahorra agua","Esfuerza juntas y muebles y empeora el golpe de ariete","Mejora el drenaje","No tiene desventajas"], re:"El exceso de presión esfuerza válvulas, conexiones, mangueras y aparatos, aumenta las fugas e intensifica el choque del golpe de ariete."},
  {id:123, q:"La presión residual (en flujo) se diferencia de la estática en que la residual se mide:", opts:["Con todas las válvulas cerradas","Solo en el medidor","Mientras el agua realmente fluye","En la red de la ciudad"], re:"La presión estática es la lectura sin flujo; la residual es la que queda en un mueble mientras se extrae agua, después de las pérdidas por fricción."},
  {id:124, q:"Si la fuente no puede mantener al menos unos 15 psi residuales en el mueble más alto, el sistema debe agregar:", opts:["Un sifón más grande","Más registros de limpieza","Una segunda ventilación","Un tanque de agua con bomba u otro medio para elevar la presión"], re:"Cuando la presión de la calle es muy baja para mantener unos 15 psi en los muebles superiores, se requiere una bomba elevadora o un sistema de tanque."},
  {id:125, q:"Para muebles alimentados por tanques de descarga, la presión mínima en flujo que se necesita comúnmente es de unos:", opts:["8 psi","30 psi","60 psi","80 psi"], re:"Los muebles comunes con tanque de descarga generalmente solo necesitan unos 8 psi en flujo, mientras que las válvulas fluxómetro necesitan unos 15 psi o más."},
  {id:126, q:"Una válvula fluxómetro (de descarga directa) normalmente requiere una presión mínima en flujo de al menos unos:", opts:["3 psi","15 psi","8 psi","2 psi"], re:"Las válvulas fluxómetro mueven un gran flujo rápidamente y normalmente requieren unos 15 psi o más en flujo para operar correctamente."},
  {id:127, q:"Por cada pie de elevación vertical, la presión estática del agua en una columna baja aproximadamente:", opts:["0.10 psi","1.0 psi","0.43 psi","2.31 psi"], re:"El agua pierde unos 0.43 psi por pie de altura (se requieren 2.31 pies de columna para hacer 1 psi), por eso los edificios altos ven menor presión arriba."},
  {id:128, q:"Una elevación de 50 pies reduce la presión estática en aproximadamente:", opts:["Unos 5 psi","Unos 50 psi","Unos 100 psi","Unos 22 psi"], re:"A unos 0.43 psi por pie, 50 pies de elevación quitan unos 21 a 22 psi de presión estática del suministro."},
  {id:129, q:"Una PRV se ajusta normalmente:", opts:["Girando un tornillo de ajuste que fija la tensión del resorte","Reemplazando el resorte con cobre","Calentando el cuerpo","Agregando un filtro más grande"], re:"Girar el tornillo de ajuste cambia la fuerza del resorte sobre el diafragma, fijando la presión reducida aguas abajo."},
  {id:130, q:"La mayoría de las válvulas reductoras de presión usadas en casas se ajustan para entregar una presión aguas abajo de aproximadamente:", opts:["5 a 10 psi","45 a 60 psi","90 a 110 psi","120 a 150 psi"], re:"Las PRV se ajustan comúnmente cerca de 45 a 60 psi, cómodamente por debajo del límite de 80 psi y con buen desempeño en los muebles."},
  {id:131, q:"Una PRV defectuosa o atascada abierta normalmente se manifiesta como:", opts:["Nada de agua","Agua fría que se vuelve caliente","Presión aguas abajo que sube hacia la presión de la red","Una ventilación bloqueada"], re:"Si una PRV falla abierta o se rasga su diafragma, la presión aguas abajo sube hacia la presión total de la red y puede superar 80 psi."},
  {id:132, q:"La presión doméstica excesivamente alta daña más comúnmente aparatos como:", opts:["Luminarias","Coladeras de piso","Ventilaciones de techo","Lavavajillas, lavadoras y calentadores de agua"], re:"Los aparatos que usan agua y sus válvulas de llenado y mangueras se esfuerzan con la presión alta, lo que acorta su vida y causa fugas."},
  {id:133, q:"El filtro antes de una PRV está ahí principalmente para:", opts:["Captar arenilla y residuos que podrían alojarse en el asiento de la válvula","Reducir la presión","Agregar cloro","Medir el flujo"], re:"El sedimento puede mantener abierto el asiento del regulador o hacer que se desvíe; el filtro captura los residuos para que la PRV siga funcionando."},
  {id:134, q:"Un regulador de presión de 1-1/2 pulgadas o más grande generalmente:", opts:["Siempre debe tener dos filtros","No requiere un filtro separado","No se puede usar en agua potable","Debe instalarse al revés"], re:"Los códigos comúnmente eximen a los reguladores de 1-1/2 pulgadas y más grandes del requisito de filtro separado por su construcción y flujo."},
  {id:135, q:"La carga que los muebles imponen a un tubo de suministro de agua se expresa en:", opts:["Unidades de mueble de drenaje (DFU)","BTU","Unidades de mueble de suministro de agua (WSFU)","Decibeles"], re:"La demanda de suministro de agua se contabiliza en unidades de mueble de suministro de agua (WSFU), que luego se convierten en un flujo pico probable en gpm."},
  {id:136, q:"Las unidades de mueble totales se convierten en una demanda pico probable en galones por minuto usando:", opts:["La ley de Ohm","La tabla de sellos de sifón","La fórmula de pendiente","Una tabla de demanda o la curva de Hunter"], re:"Una tabla de demanda (curva de Hunter) da el flujo simultáneo probable en gpm para un número dado de unidades de mueble."},
  {id:137, q:"La demanda en gpm correspondiente a un número de unidades de mueble es mayor cuando los inodoros se sirven con:", opts:["Válvulas fluxómetro (de descarga directa)","Tanques de descarga","Llaves de manguera","Coladeras de piso"], re:"Las válvulas fluxómetro extraen un gran flujo instantáneo, por lo que para el mismo conteo de unidades la demanda probable en gpm es mayor que con tanques de descarga."},
  {id:138, q:"Para un mueble con conexiones de agua caliente y fría, cada valor separado de unidades de caliente y fría puede tomarse como aproximadamente:", opts:["El total listado completo","Tres cuartos del total listado","El doble del total listado","Cero"], re:"Como la caliente y la fría no se usan a pleno simultáneamente, cada rama se cuenta comúnmente como tres cuartos del total listado de unidades."},
  {id:139, q:"La pérdida por fricción en un tubo de agua aumenta cuando:", opts:["El diámetro del tubo aumenta","Solo el agua se enfría","La velocidad de flujo aumenta o el tubo es más largo","La presión se reduce"], re:"La pérdida por fricción sube con mayor velocidad, recorridos más largos, menor diámetro y tubo más rugoso, consumiendo la presión disponible."},
  {id:140, q:"Para limitar el ruido y la corrosión por erosión, la velocidad del agua fría en tubo de cobre suele mantenerse en o por debajo de unos:", opts:["2 fps","20 fps","40 fps","8 fps"], re:"Los diseñadores comúnmente limitan la velocidad del agua fría cerca de 8 fps en cobre para evitar ruido y erosión de la pared del tubo."},
  {id:141, q:"La velocidad del agua caliente en tubo de cobre generalmente se mantiene más baja que la del agua fría, en unos:", opts:["5 fps","8 fps","15 fps","25 fps"], re:"El agua caliente es más agresiva, por lo que la velocidad en cobre suele limitarse a unos 5 fps para reducir la corrosión por erosión."},
  {id:142, q:"Para el mismo caudal, un tubo de menor diámetro tendrá:", opts:["Menor velocidad y menos pérdida por fricción","Mayor velocidad y mayor pérdida por fricción","Sin cambio en la fricción","Menos ruido"], re:"Reducir el diámetro fuerza el mismo flujo por un área menor, elevando bruscamente la velocidad y la pérdida por fricción."},
  {id:143, q:"La 'longitud desarrollada' usada al dimensionar un tubo de agua significa:", opts:["Solo la distancia en línea recta","El diámetro del tubo","El recorrido medido total más las tolerancias por conexiones y válvulas","Solo la elevación vertical"], re:"La longitud desarrollada es el recorrido real del tubo más la longitud equivalente añadida por conexiones y válvulas, usada para sumar la pérdida por fricción."},
  {id:144, q:"En un problema típico de dimensionamiento, la presión disponible para vencer la fricción del tubo es igual a la presión de la fuente menos:", opts:["Solo el costo del medidor","El color del tubo","El número de muebles","La pérdida por elevación (estática), la presión necesaria en el mueble y las pérdidas de los dispositivos"], re:"De la presión de la fuente se resta la pérdida por elevación, la presión mínima requerida en el mueble y las pérdidas del medidor/regulador/antirretorno; el resto queda para la fricción."},
  {id:145, q:"Agregar muchos codos y conexiones a un recorrido afecta el dimensionamiento principalmente al:", opts:["Aumentar la longitud equivalente y por tanto la pérdida por fricción","Bajar la demanda","Reducir la velocidad","Aumentar la presión estática"], re:"Cada conexión añade longitud equivalente; muchas conexiones elevan la pérdida por fricción total, lo que puede requerir un tubo más grande."},
  {id:146, q:"A una llave de manguera contabilizada para el dimensionamiento se le asignan unidades de mueble porque:", opts:["Nunca usa agua","Puede extraer un flujo continuo considerable","Siempre está cerrada","Reduce la demanda"], re:"Una llave de manguera puede extraer un flujo alto y sostenido, por lo que lleva unidades de mueble; las llaves de manguera adicionales en el mismo tubo pueden contarse a una tasa reducida."},
  {id:147, q:"Una demanda de flujo continuo, como la de un suministro de riego, se maneja en el dimensionamiento al:", opts:["Ignorarla","Reducir a la mitad el tamaño del tubo","Sumar sus gpm por separado a la demanda de unidades de mueble","Contarla como una unidad de mueble"], re:"Los flujos continuos no siguen el modelo intermitente de unidades de mueble, por lo que sus gpm se suman directamente a la demanda de la tubería afectada."},
  {id:148, q:"En comparación con un recorrido largo, un recorrido corto del mismo tubo al mismo flujo tendrá:", opts:["Más pérdida por fricción","La misma pérdida total","Sin velocidad","Menos pérdida por fricción total"], re:"La pérdida por fricción es proporcional a la longitud, por lo que un recorrido más corto del mismo tubo y flujo pierde menos presión por fricción."},
  {id:149, q:"Dimensionar la distribución de agua para que cada mueble reciba flujo adecuado en uso pico es importante porque:", opts:["Varios muebles pueden operar a la vez y competir por el flujo","Baja la factura de agua","Todos los tubos deben coincidir","Elimina la necesidad de un medidor"], re:"El tubo debe conducir la demanda simultánea probable para que abrir un mueble no deje sin agua a otro en los periodos de mayor uso."},
  {id:150, q:"Sobredimensionar el tubo de distribución de agua muy por encima de la demanda puede causar:", opts:["Mejor entrega de agua caliente","Largas esperas de agua caliente y desperdicio de agua y energía","Solo problemas de menor fricción","Mayor presión en los muebles"], re:"El tubo de agua caliente excesivamente grande retiene más agua enfriada, por lo que los usuarios esperan más y desperdician agua y energía mientras se purga."},
  {id:151, q:"La demanda probable (de diseño) en el suministro de un edificio normalmente es menor que la suma de todos los flujos de los muebles porque:", opts:["Los muebles nunca funcionan","El medidor bloquea el flujo","No todos los muebles se usan en el mismo instante","La presión es ilimitada"], re:"Los métodos de unidades de mueble consideran la baja probabilidad de que todos los muebles funcionen a la vez, por lo que la demanda de diseño es menor que el total aritmético."},
  {id:152, q:"El golpe de ariete es el golpeteo o choque que ocurre cuando:", opts:["Un tubo es demasiado grande","La presión es demasiado baja","Un sifón es demasiado profundo","Una válvula de cierre rápido detiene de golpe el agua en movimiento"], re:"Detener bruscamente una columna de agua en movimiento convierte su impulso en una sobrepresión que sacude la tubería."},
  {id:153, q:"Un amortiguador de golpe de ariete controla la sobrepresión al:", opts:["Proporcionar un colchón de aire sellado que absorbe el choque","Filtrar el agua","Aumentar la presión estática","Calentar el tubo"], re:"El amortiguador contiene una cámara de aire o pistón sellado permanentemente que se comprime para absorber el pico de presión."},
  {id:154, q:"El código exige protección contra golpe de ariete dondequiera que el sistema tenga:", opts:["Solo tanques de descarga","Válvulas de acción rápida (cierre rápido)","Ningún aparato","Tubo galvanizado"], re:"Los sistemas con válvulas de acción rápida deben tener dispositivos aprobados para absorber el golpe que producen esas válvulas al cerrar."},
  {id:155, q:"Los amortiguadores de golpe de ariete fabricados deben cumplir con:", opts:["Solo ASSE 1003","Solo NSF 14","ASSE 1010 o PDI-WH 201","Ninguna norma"], re:"Los amortiguadores aprobados cumplen ASSE 1010 o PDI-WH 201, que fijan requisitos de desempeño y durabilidad."},
  {id:156, q:"Un amortiguador de golpe de ariete debe instalarse:", opts:["Lo más lejos posible de la válvula","Solo en el medidor","En la columna de ventilación","Lo más cerca posible de la válvula de cierre rápido"], re:"Colocar el amortiguador cerca de la válvula de cierre rápido le permite absorber la sobrepresión antes de que viaje por la tubería."},
  {id:157, q:"Una causa común de golpe de ariete repentino en una lavandería es la:", opts:["Válvula solenoide (de cierre rápido) de una lavadora","Coladera de piso","Ventilación del sifón","Medidor de agua"], re:"Las válvulas solenoide de la lavadora se cierran de golpe, por lo que comúnmente se colocan amortiguadores en sus suministros de caliente y fría."},
  {id:158, q:"Un lavavajillas, que también usa una válvula de llenado de cierre rápido, se protege mejor con un amortiguador en:", opts:["La línea de drenaje","Su suministro de agua caliente","La ventilación","La línea de gas"], re:"Un lavavajillas extrae agua caliente por una válvula de cierre rápido, por lo que un amortiguador en su suministro caliente absorbe el choque resultante."},
  {id:159, q:"Las cámaras de aire antiguas (tubos verticales tapados) con el tiempo dejan de funcionar porque:", opts:["Se oxidan y se cierran","Crecen demasiado","Se anegan al disolverse el aire atrapado en el agua","Se congelan permanentemente"], re:"El aire de un tubo simple se disuelve gradualmente en el agua y la cámara se llena, por lo que se prefieren los amortiguadores sellados modernos."},
  {id:160, q:"Un amortiguador mecánico (tipo pistón) se prefiere sobre una cámara de aire simple porque:", opts:["No cuesta nada","No necesita soporte","Aumenta la presión","Mantiene su carga de aire sellada y no se anega"], re:"El pistón o fuelle sellado mantiene el aire separado del agua, por lo que el dispositivo sigue absorbiendo el choque a largo plazo."},
  {id:161, q:"Además de los amortiguadores, el golpe de ariete puede reducirse al:", opts:["Bajar la presión excesiva y asegurar los tubos sueltos","Aumentar la velocidad","Quitar todas las válvulas","Agregar más codos"], re:"Menor presión y velocidad más lenta debilitan la sobrepresión, y el tubo bien sujeto transmite menos ruido y movimiento."},
  {id:162, q:"Una mayor velocidad del agua en un tubo tiende a hacer el golpe de ariete:", opts:["Más débil","Más fuerte cuando una válvula cierra","Desaparecer","Independiente de la velocidad"], re:"Cuanto más rápida es la columna en movimiento, más impulso hay que detener, por lo que un cierre rápido produce una sobrepresión mayor."},
  {id:163, q:"La tubería de agua suelta y sin sujetar empeora el golpe de ariete principalmente porque el tubo:", opts:["Tiene más fugas","Se calienta más","Puede moverse y golpear contra la estructura cuando llega la sobrepresión","Cambia de tamaño"], re:"El tubo sin apoyo se sacude y golpea la estructura durante la sobrepresión; una buena sujeción limita el movimiento y el ruido."},
  {id:164, q:"Un amortiguador tamaño 'AA' o 'A' según PDI-WH 201 normalmente está pensado para:", opts:["Una columna entera de un edificio alto","Una bomba contra incendios","Una línea de cloaca","Un solo mueble o aparato residencial"], re:"Los tamaños PDI como AA y A se dimensionan por unidades de mueble para conexiones residenciales individuales como una lavadora o un lavavajillas."},
  {id:165, q:"Una ubicación accesible es importante para un amortiguador de golpe de ariete para que pueda:", opts:["Inspeccionarse o reemplazarse si falla","Pintarse","Usarse como válvula de cierre","Calentarse"], re:"Los amortiguadores pueden perder eficacia con el tiempo, por lo que el acceso permite darles servicio o reemplazarlos cuando sea necesario."},
  {id:166, q:"Las válvulas de cierre rápido incluyen todas las siguientes EXCEPTO:", opts:["Una válvula solenoide de lavadora","Una válvula de compuerta girada lentamente","Una válvula de llenado de lavavajillas","Una solenoide eléctrica en una máquina de hielo"], re:"Una válvula de compuerta cerrada lentamente a mano no se cierra de golpe, por lo que no es del tipo de cierre rápido que produce golpe severo."},
  {id:167, q:"Si los tubos siguen golpeando después de agregar un solo amortiguador, una causa probable restante es:", opts:["El agua está demasiado limpia","Demasiados registros de limpieza","Presión excesiva del sistema o tubería sin sujetar en otro lado","Un sello de sifón profundo"], re:"El golpe a menudo tiene varias causas; la presión alta y los recorridos de tubo sueltos pueden seguir causando ruido aun después de instalar un amortiguador."},
  {id:168, q:"La longitud desarrollada de la tubería de agua caliente desde la fuente hasta un mueble generalmente se limita a unos:", opts:["10 pies","200 pies","Sin límite","50 pies"], re:"Los códigos comúnmente limitan la longitud desarrollada del tubo de agua caliente a un mueble a unos 50 pies, o debe proveerse un sistema de recirculación o de cable calefactor."},
  {id:169, q:"Un circuito de recirculación de agua caliente se usa principalmente para:", opts:["Mantener el agua caliente cerca de los muebles para que el usuario espere y desperdicie menos","Aumentar la presión del agua","Filtrar el agua","Prevenir el retorno"], re:"La recirculación mantiene el agua caliente moviéndose cerca de los muebles para que llegue rápido en vez de tirar agua fría al drenaje."},
  {id:170, q:"En un sistema de recirculación, la tubería de recirculación se considera una:", opts:["Línea de drenaje","Fuente de agua caliente o templada para medir el límite de 50 pies","Ventilación","Rama de agua fría"], re:"Como el circuito entrega agua caliente cerca de los muebles, cuenta como la fuente desde la que se mide la longitud desarrollada máxima."},
  {id:171, q:"Para ahorrar energía, la tubería de agua caliente y de recirculación generalmente debe estar:", opts:["Enterrada en concreto","Pintada de rojo","Aislada","Desnuda para inspección"], re:"Aislar la tubería de agua caliente y de recirculación reduce la pérdida de calor en reposo, como exige el código de energía."},
  {id:172, q:"Para reducir el riesgo de quemaduras, el agua caliente entregada a tinas y regaderas comúnmente se limita a un máximo de aproximadamente:", opts:["100°F","160°F","180°F","120°F"], re:"Unos 120°F es la temperatura máxima común de entrega para regaderas y tinas para reducir el riesgo de quemaduras."},
  {id:173, q:"Una válvula mezcladora termostática (de templado) en el calentador de agua se usa para:", opts:["Mezclar caliente y fría para entregar agua a una temperatura fijada más segura","Aumentar la presión","Prevenir el retorno","Drenar el tanque"], re:"Una válvula de templado ASSE 1017 mezcla el agua caliente del tanque con fría a una temperatura más baja controlada para el sistema de distribución."},
  {id:174, q:"Almacenar el agua más caliente que la temperatura de entrega y templarla hacia abajo se hace a menudo para:", opts:["Desperdiciar energía","Limitar el crecimiento de Legionella y aun así entregar temperaturas seguras","Bajar la presión","Aumentar el flujo"], re:"Una temperatura de almacenamiento más alta inhibe la bacteria Legionella, mientras una válvula mezcladora templa el agua entregada a un nivel seguro."},
  {id:175, q:"La expansión térmica ocurre en un calentador de agua porque el agua caliente:", opts:["Se contrae","Se vuelve más densa","Se expande y aumenta de volumen","Pierde presión"], re:"El agua se expande al calentarse; en un sistema cerrado ese volumen adicional no tiene a dónde ir, por lo que la presión sube."},
  {id:176, q:"El agua calentada de unos 50°F a 120°F se expande aproximadamente:", opts:["0.02% (casi nada)","20% en volumen","50% en volumen","2% en volumen"], re:"Calentar agua de unos 50°F a 120°F aumenta su volumen aproximadamente un 2 por ciento, lo que eleva la presión en un sistema cerrado."},
  {id:177, q:"Se requiere un tanque de expansión en un calentador de agua siempre que el sistema esté:", opts:["Cerrado por una válvula de retención, PRV o antirretorno","Abierto a la atmósfera","Solo en un pozo","Hecho de plástico"], re:"Una válvula de retención, regulador de presión o dispositivo antirretorno cierra el sistema, por lo que se requiere un tanque o dispositivo de expansión para absorber la expansión térmica."},
  {id:178, q:"Un tanque de expansión térmica normalmente se conecta a:", opts:["La salida de agua caliente lejos del calentador","La tubería de suministro de agua fría al calentador","La línea de drenaje","La columna de ventilación"], re:"El tanque de expansión se instala en el suministro de agua fría al calentador, aguas abajo de cualquier válvula de retención, PRV o antirretorno."},
  {id:179, q:"Un tanque de expansión de diafragma absorbe la expansión usando:", opts:["Un serpentín calefactor","Una válvula de retención","Un colchón de aire precargado detrás de un diafragma flexible","Una malla filtrante"], re:"Al expandirse, el agua empuja contra el diafragma y comprime el aire cautivo, manteniendo la presión dentro de límites seguros."},
  {id:180, q:"Para mejor desempeño, la precarga de aire de un tanque de expansión debe ajustarse a:", opts:["Cero","El doble de la presión del sistema","Siempre 150 psi","La presión estática (sin flujo) del agua del sistema"], re:"Igualar la precarga a la presión estática del sistema deja el diafragma neutro para que el tanque acepte la expansión apenas sube la presión."},
  {id:181, q:"Sin control de expansión térmica en un sistema cerrado, el síntoma más probable es:", opts:["La válvula de alivio T&P goteando cuando el calentador enciende","Baja presión","Falta de agua caliente","Un drenaje bloqueado"], re:"La presión creciente por la expansión puede levantar repetidamente la válvula de alivio T&P, haciéndola gotear hasta que se agrega control de expansión."},
  {id:182, q:"La válvula de alivio de temperatura y presión (T&P) de un calentador comúnmente se ajusta para abrir a no más de:", opts:["50 psi","150 psi","80 psi","300 psi"], re:"Las válvulas T&P residenciales normalmente se ajustan para aliviar a 150 psi (y unos 210°F) para proteger el tanque de la sobrepresión."},
  {id:183, q:"Un tanque de expansión que ha perdido su carga de aire:", opts:["Funciona mejor","Sube la presión a propósito","Se llena de agua y deja de absorber la expansión","Drena el calentador"], re:"Un tanque anegado no puede comprimirse, por lo que ya no controla la expansión y la válvula de alivio puede empezar a gotear de nuevo."},
  {id:184, q:"Una bomba de recirculación en un circuito doméstico de agua caliente normalmente es:", opts:["Una bomba elevadora de alta presión","Un eyector de aguas negras","Una bomba de vacío","Un pequeño circulador que mueve el agua por el circuito"], re:"Un pequeño circulador de baja carga mantiene el agua caliente moviéndose por el circuito; no es una bomba elevadora de presión para todo el sistema."},
  {id:185, q:"Donde la presión de la red pública es muy baja para servir al edificio, el suministro puede complementarse con:", opts:["Un tanque elevado, un sistema hidroneumático o una bomba elevadora","Un sifón más grande","Una segunda ventilación","Una coladera de piso"], re:"La presión insuficiente de la red se supera con un tanque elevado (por gravedad), un tanque hidroneumático de presión o una bomba elevadora de presión de agua."},
  {id:186, q:"Un tanque elevado (por gravedad) de la casa suministra presión al edificio al:", opts:["Hacer funcionar una bomba continuamente","Usar la altura del agua almacenada para crear presión estática","Agregar químicos","Calentar el agua"], re:"El agua almacenada en alto en el edificio cae por gravedad, y su elevación proporciona la presión estática a los pisos inferiores."},
  {id:187, q:"Un tanque hidroneumático (de presión) mantiene la presión usando:", opts:["Un elemento calefactor","Solo una válvula de retención","Un volumen cautivo de aire comprimido sobre el agua","Solo la gravedad"], re:"El aire comprimido atrapado sobre el agua en un tanque sellado empuja el agua hacia afuera bajo presión, suavizando el ciclo de la bomba."},
  {id:188, q:"En un edificio alto, la presión del agua en los pisos superiores es menor que en los inferiores debido a:", opts:["Medidores más pequeños arriba","Agua más fría","Menos muebles","La pérdida de presión estática con la altura"], re:"Cada pie de elevación cuesta unos 0.43 psi, por lo que los pisos superiores ven menor presión y pueden necesitar una bomba elevadora o zonificación."},
  {id:189, q:"Una bomba elevadora que puede funcionar con la válvula de descarga cerrada a menudo necesita protección contra:", opts:["Sobrecalentamiento o presión excesiva (p. ej., protección por bajo flujo o de alivio)","Solo el retorno","Solo el congelamiento","Solo el ruido"], re:"Una bomba bloqueada contra un sistema cerrado puede sobrecalentarse o sobrepresurizarse, por lo que controles o una vía de alivio la protegen."},
  {id:190, q:"Los edificios altos a menudo se dividen en zonas de presión para que los pisos inferiores no experimenten:", opts:["Muy poca presión","Presión excesivamente alta de toda la columna superior","Retorno","Bloqueo por aire"], re:"Sin zonificación, los pisos más bajos verían toda la carga estática del agua que tienen encima, superando los límites seguros de presión."},
  {id:191, q:"Cada suministro de mueble comúnmente tiene su propia:", opts:["Ventilación","Sifón","Llave de cierre (stop) accesible","Registro de limpieza"], re:"Una llave de cierre de mueble accesible permite aislar un solo mueble para repararlo sin apagar todo el edificio."},
  {id:192, q:"La convención para las llaves de suministro de muebles, de frente al mueble, coloca el agua caliente a la:", opts:["Derecha y la fría a la izquierda","Arriba","Abajo","Izquierda y la fría a la derecha"], re:"Por convención de larga data, la caliente va a la izquierda y la fría a la derecha en un mueble, como espera el usuario."},
  {id:193, q:"Un dispositivo antirretorno o válvula de retención protege el suministro potable al:", opts:["Permitir el flujo en un solo sentido, hacia el edificio","Aumentar la presión","Filtrar el agua","Reducir la temperatura"], re:"Estos dispositivos permiten el flujo solo hacia los muebles y bloquean el flujo inverso que podría aspirar contaminación de regreso a la tubería potable."},
  {id:194, q:"Una conexión cruzada es peligrosa para el suministro potable porque podría permitir:", opts:["Mayor presión","Que agua no potable entre a la tubería de agua potable","Drenaje más rápido","Facturas más bajas"], re:"Una conexión cruzada une sistemas potable y no potable; si el flujo se invierte, agua contaminada puede entrar al suministro de agua potable."},
  {id:195, q:"El sifonaje inverso (back-siphonage) es una forma de retorno causada por:", opts:["Alta presión aguas abajo","Una válvula cerrada","Presión negativa (subatmosférica) en el suministro que jala el agua hacia atrás","Expansión térmica"], re:"Cuando la presión del suministro cae por debajo de la atmosférica, la succión puede jalar agua no potable de regreso por una conexión cruzada al sistema."},
  {id:196, q:"Una llave de manguera que alimenta una manguera de jardín debe protegerse contra el sifonaje inverso con:", opts:["Un regulador de presión","Un segundo medidor","Un tubo más grande","Un rompevacío de conexión de manguera"], re:"Un rompevacío de conexión de manguera rompe cualquier sifón para que el agua contaminada no pueda jalarse de regreso por la manguera al suministro potable."},
  {id:197, q:"Un espacio de aire (air gap) protege el suministro potable al proporcionar:", opts:["Un espacio vertical sin obstrucción entre la salida y el borde de rebose","Una válvula de retención","Más presión","Un filtro"], re:"Un air gap es una separación vertical física para que el agua contaminada nunca pueda sifonarse de regreso a la salida de suministro."},
  {id:198, q:"Donde una bomba elevadora extrae de una red de la ciudad, los códigos se preocupan de que la succión pueda:", opts:["Mejorar la calidad del agua","Crear presión negativa que sifonee contaminación de regreso a la red","Aumentar la presión de la red","Calentar la red"], re:"Una bomba que jala fuerte de la red puede bajar la presión por debajo de la atmosférica y sifonear contaminantes, por lo que se requieren medidas de protección."},
  {id:199, q:"Un conjunto antirretorno de principio de presión reducida (RP) se usa para proteger el suministro potable donde:", opts:["No existe peligro","La presión es menor de 8 psi","Debe protegerse una conexión cruzada de alto peligro","El tubo es de plástico"], re:"El conjunto RP proporciona el mayor nivel de protección y se requiere donde una conexión cruzada de alto peligro amenaza el agua potable."},
  {id:200, q:"Después de reparaciones que abren la tubería potable, un paso común para proteger la calidad del agua antes de usarla es:", opts:["Agregar más presión","Quitar el medidor","Bajar la temperatura","Lavar y, donde se requiera, desinfectar la tubería afectada"], re:"La tubería potable abierta o nueva se lava y, donde se requiere, se desinfecta para que los contaminantes introducidos durante el trabajo no lleguen a los usuarios."},
  {id:201, q:"Una unidad de mueble de desagüe (DFU) es una medida usada para:", opts:["Expresar la carga probable de desagüe que un mueble impone al sistema","Fijar la presión del suministro de agua","Calificar la potencia de una bomba","Dimensionar el circuito eléctrico"], re:"Una DFU es un valor numérico asignado a un mueble que representa su carga probable de descarga, usado para dimensionar desagües y cloacas."},
  {id:202, q:"En las tablas de unidades de mueble de la UPC, un solo lavabo privado se califica generalmente en unos:", opts:["2 DFU","1 DFU","6 DFU","3 DFU"], re:"Un solo lavabo lleva alrededor de 1 unidad de mueble de desagüe porque su carga de descarga es pequeña."},
  {id:203, q:"A una tina (bañera) estándar se le asigna comúnmente una carga de desagüe de unos:", opts:["8 DFU","1 DFU","2 DFU","4 DFU"], re:"A una tina se le asignan típicamente cerca de 2 unidades de mueble de desagüe en las tablas de la UPC."},
  {id:204, q:"A un fregadero de cocina doméstico se le califica de desagüe generalmente en unos:", opts:["1/2 DFU","6 DFU","10 DFU","2 DFU"], re:"A un fregadero de cocina residencial se le asignan comúnmente cerca de 2 unidades de mueble de desagüe."},
  {id:205, q:"A un inodoro privado (1.6 gpf) se le asigna típicamente una carga de desagüe de unos:", opts:["3 DFU","8 DFU","12 DFU","1 DFU"], re:"A un inodoro privado se le califica comúnmente en cerca de 3 unidades de mueble de desagüe, la mayor carga de un solo mueble residencial."},
  {id:206, q:"A medida que aumentan las unidades de mueble totales que lleva un desagüe, el tamaño de tubo requerido generalmente:", opts:["Se hace más pequeño","Se hace más grande","Se vuelve opcional","Permanece igual"], re:"Más unidades de mueble significan más flujo probable, por eso el desagüe debe ser más grande para llevar la carga por gravedad."},
  {id:207, q:"El número máximo de unidades de mueble que un desagüe horizontal puede llevar depende principalmente de su diámetro y de su:", opts:["Longitud de la ventilación","Color","Pendiente (declive)","Marca de la conexión"], re:"Las tablas de capacidad se basan en el diámetro y la pendiente del tubo, ya que una pendiente mayor permite que un tubo lleve más unidades de mueble."},
  {id:208, q:"Cuando dos o más muebles descargan en un mismo desagüe, ese desagüe debe dimensionarse para:", opts:["La mitad del total de unidades de mueble","Una unidad de mueble sin importar la cantidad","Solo el mueble individual más grande","El total combinado de unidades de mueble de todos los muebles servidos"], re:"Un desagüe común se dimensiona para la suma de las unidades de mueble que sirve, de modo que pueda llevar la carga combinada."},
  {id:209, q:"Un desagüe de derivación horizontal de 2 pulgadas es más apropiado para:", opts:["Una coladera de piso o un grupo pequeño de fregaderos y tinas","Una cloaca de edificio de 6 pulgadas","Un solo inodoro","Un grupo de varios inodoros"], re:"Una derivación de 2 pulgadas conviene para muebles ligeros como coladeras de piso, tinas y fregaderos; los inodoros requieren un mínimo de 3 pulgadas."},
  {id:210, q:"Un desagüe de mueble se define como el desagüe que va desde:", opts:["El registro de limpieza a la calle","El sifón de un mueble a la unión con cualquier otro tubo de desagüe","La ventilación del techo al ático","El medidor de agua al mueble"], re:"Un desagüe de mueble va desde el sifón del mueble hasta el punto donde se une a otro tubo de desagüe."},
  {id:211, q:"Un tubo de desagüe nunca puede ser más pequeño que:", opts:["La ventilación que lo sirve","El doble del tamaño del sifón","El sifón o el brazo del sifón del mueble que sirve","La mitad del tamaño del sifón"], re:"Un desagüe de mueble no puede ser más pequeño que el sifón y el brazo del sifón que sirve, o el flujo quedaría restringido."},
  {id:212, q:"Comparado con un mueble privado, el mismo mueble en uso público a menudo recibe:", opts:["Ninguna unidad de mueble","Menos unidades de mueble","Siempre las mismas unidades de mueble","Más unidades de mueble"], re:"Los muebles públicos se usan con más frecuencia, por eso las tablas a menudo les asignan un valor de unidad de mueble mayor que a los privados."},
  {id:213, q:"El tamaño mínimo de sifón y desagüe para un lavabo residencial estándar es:", opts:["1-1/4 pulgada","2 pulgadas","3 pulgadas","4 pulgadas"], re:"Un lavabo usa un sifón y desagüe mínimo de 1-1/4 pulgada porque su carga de descarga es ligera."},
  {id:214, q:"Una regadera (ducha) se sirve típicamente con un sifón y desagüe de al menos:", opts:["1-1/4 pulgada","2 pulgadas","3 pulgadas","4 pulgadas"], re:"Una regadera requiere un sifón y desagüe mínimo de 2 pulgadas para llevar su flujo sin que se desborde."},
  {id:215, q:"Sobredimensionar un desagüe muy por encima de las unidades de mueble requeridas puede ser indeseable porque puede:", opts:["Eliminar la necesidad de una ventilación","Llevar el residuo demasiado rápido","Reducir la acción de arrastre y dejar que los sólidos se asienten","Costar siempre menos"], re:"Un desagüe sobredimensionado corre con poca lámina, reduciendo la velocidad de autolimpieza, por lo que los sólidos se asientan y tapan la línea."},
  {id:216, q:"El desagüe del edificio y la cloaca del edificio se dimensionan a partir de:", opts:["El número de ventanas","La capacidad del calentador de agua","Solo el área del techo","El total de unidades de mueble de desagüe de todo el edificio"], re:"El desagüe y la cloaca del edificio se dimensionan para la carga total de unidades de mueble de todos los muebles que descargan en ellos."},
  {id:217, q:"Un fregadero de cocina con triturador de desperdicios y lavavajillas generalmente:", opts:["Puede recibir carga de desagüe adicional y un desagüe de 2 pulgadas","Debe drenar a la ventilación","No necesita sifón","Lleva la misma carga que un lavabo"], re:"Los aparatos añadidos aumentan la descarga, por eso al fregadero se le suele dar un desagüe de 2 pulgadas y un conteo de unidades de mueble mayor."},
  {id:218, q:"Los valores de unidad de mueble existen para que los diseñadores puedan:", opts:["Evitar usar tablas por completo","Convertir muebles distintos a un valor de carga común para dimensionar","Fijar la presión del gas","Elegir colores de pintura"], re:"Al convertir cada mueble a una unidad común, se pueden sumar grupos mixtos de muebles para dimensionar el desagüe."},
  {id:219, q:"Un desagüe horizontal de 3 pulgadas generalmente lleva:", opts:["Nunca ningún inodoro","Solo un lavabo","Más unidades de mueble que un desagüe de 2 pulgadas con la misma pendiente","Menos unidades de mueble que un desagüe de 1-1/2 pulgada"], re:"Un diámetro mayor lleva una carga de unidades de mueble más alta, por eso un desagüe de 3 pulgadas maneja más que uno de 2 pulgadas con la misma pendiente."},
  {id:220, q:"Cuando se usan tablas de unidades de mueble, los valores representan:", opts:["La presión de ruptura del tubo","La longitud de la ventilación","Flujo pleno simultáneo garantizado de cada mueble","Una carga probable, no un pico simultáneo"], re:"Las unidades de mueble reflejan la probabilidad de que los muebles descarguen al mismo tiempo, no que todos corran a flujo pleno a la vez."},
  {id:221, q:"A los tubos de desagüe horizontal de 2-1/2 pulgadas y menores se les da comúnmente una pendiente mínima de:", opts:["1/4 de pulgada por pie","1 pulgada por pie","1/2 pulgada por pie","1/8 de pulgada por pie"], re:"Los desagües horizontales pequeños se inclinan al menos 1/4 de pulgada por pie para que el residuo fluya por gravedad y los sólidos sean arrastrados."},
  {id:222, q:"A los desagües horizontales más grandes (3 pulgadas y mayores) se les puede permitir una pendiente de tan poco como:", opts:["Solo 1/4 de pulgada por pie","1/8 de pulgada por pie donde se apruebe","1 pulgada por pie","Sin mínimo"], re:"Los desagües de mayor diámetro pueden correr con una pendiente más plana de 1/8 de pulgada por pie porque su mayor sección transversal aún mantiene el flujo."},
  {id:223, q:"Un tubo de desagüe con pendiente demasiado pronunciada puede causar problemas porque:", opts:["Siempre se congela","La ventilación es innecesaria","El líquido puede escurrir y dejar atrás los sólidos","El agua fluye cuesta arriba"], re:"En una pendiente muy pronunciada el agua adelanta a los sólidos, dejándolos en el tubo donde se acumulan y lo tapan."},
  {id:224, q:"Un desagüe horizontal corrido perfectamente nivelado (sin pendiente) tiende a:", opts:["Limpiarse por arrastre","Drenar por capilaridad","Fluir más rápido","Permitir que el residuo se estanque y los sólidos se asienten"], re:"Sin pendiente no hay flujo por gravedad, por lo que el residuo se estanca en el tubo y los sólidos se asientan y lo bloquean."},
  {id:225, q:"Una pendiente de 1/4 de pulgada por pie significa que el tubo baja:", opts:["1/4 de pulgada por cada pie de tramo horizontal","1 pie por cada 1/4 de pulgada","4 pulgadas por pie","1/4 de pulgada en toda su longitud"], re:"Una pendiente de 1/4 de pulgada por pie hace que el tubo descienda un cuarto de pulgada de caída por cada pie de distancia horizontal."},
  {id:226, q:"El propósito de mantener una pendiente de desagüe adecuada es conservar el flujo a una velocidad que sea:", opts:["Lo más lenta posible","De autolimpieza para que los sólidos sean arrastrados","Exactamente cero","Suficientemente rápida para salpicar por la ventilación"], re:"La pendiente correcta produce una velocidad de autolimpieza que mantiene los sólidos en movimiento y evita que el tubo se ensucie."},
  {id:227, q:"En un tramo horizontal de 12 pies, una pendiente de 1/4 de pulgada por pie da una caída total de unas:", opts:["Sin caída","1 pulgada","3 pulgadas","12 pulgadas"], re:"A 1/4 de pulgada por pie, doce pies de tramo bajan unas 3 pulgadas en total (12 x 1/4 de pulgada)."},
  {id:228, q:"La tubería de desagüe depende principalmente de qué fuerza para mover el residuo?", opts:["El vacío de la ventilación","La presión del suministro de agua","La presión de una bomba","La gravedad"], re:"Un sistema de desagüe por gravedad usa la pendiente del tubo y la gravedad, no la presión, para llevar el residuo a la cloaca."},
  {id:229, q:"Un cambio de dirección en un desagüe horizontal debe hacerse con conexiones que:", opts:["Mantengan un flujo suave, como codos de barrido largo o conexiones combinadas","Inviertan la pendiente","Eliminen la pendiente","Giren el flujo bruscamente a 90 grados en horizontal"], re:"Las conexiones suaves y de barrido mantienen el residuo fluyendo y resisten las obstrucciones, mientras que los giros horizontales bruscos atrapan sólidos."},
  {id:230, q:"Si un desagüe horizontal debe correr con menos pendiente que su mínimo, el remedio usual es:", opts:["Usar un tubo más pequeño","Aumentar el diámetro del tubo o instalar una bomba","Quitar el sifón","Agregar más conexiones"], re:"Un tubo más grande lleva la carga con una pendiente más plana; donde no hay caída disponible, se usa una bomba o eyector de aguas residuales aprobado."},
  {id:231, q:"Un desagüe de edificio por debajo del nivel de la cloaca pública típicamente requiere:", opts:["Ninguna disposición especial","Solo una pendiente por gravedad más pronunciada","Un eyector de aguas residuales o bomba de sumidero para elevar el residuo","Solo una ventilación más grande"], re:"Los muebles por debajo de la cloaca no pueden drenar por gravedad, así que su residuo se recoge en un sumidero y se bombea hasta el desagüe por gravedad."},
  {id:232, q:"En un desagüe con pendiente, el término 'invert' (solera) se refiere a:", opts:["El recubrimiento exterior","La tapa del registro","La parte interior superior del tubo","La superficie interior más baja del tubo"], re:"La solera es el punto interior más bajo del tubo; la pendiente se mide a lo largo de la solera para fijar la caída adecuada."},
  {id:233, q:"La pendiente correcta se verifica durante la instalación principalmente para asegurar:", opts:["Una caída continua hacia la cloaca sin panzas ni contrapendiente","Que el tubo esté nivelado","Que la ventilación sea más corta","Que el tubo se vea recto"], re:"Verificar la pendiente confirma una caída continua a la cloaca; un punto bajo (panza) o una contrapendiente retendría el residuo y lo taparía."},
  {id:234, q:"Una 'panza' (hundimiento) en un desagüe horizontal es un defecto porque:", opts:["Acelera el drenaje","Acumula agua estancada y residuo, causando obstrucciones","Mejora la ventilación","Aumenta la pendiente"], re:"Un hundimiento crea un punto bajo donde el agua y los sólidos se acumulan en lugar de seguir fluyendo, bloqueando finalmente la línea."},
  {id:235, q:"El tubo de desagüe debe soportarse a intervalos lo bastante cercanos para:", opts:["Permitir que el tubo flexione libremente","Eliminar la necesidad de pendiente","Evitar el hundimiento que destruiría la pendiente","Hacer el tubo más pesado"], re:"Soportes y abrazaderas adecuados evitan que el tubo se hunda entre apoyos, lo que crearía panzas y arruinaría la pendiente."},
  {id:236, q:"La profundidad del sello de agua de un sifón generalmente debe ser no menor de:", opts:["6 pulgadas","1/2 pulgada","1 pulgada","2 pulgadas"], re:"El sello de un sifón debe tener al menos 2 pulgadas de profundidad para que bloquee de forma confiable el gas de cloaca hacia el edificio."},
  {id:237, q:"El sello de agua de un sifón normalmente se limita a una profundidad máxima de unas:", opts:["4 pulgadas","12 pulgadas","24 pulgadas","Sin máximo"], re:"Los sellos de sifón se mantienen entre 2 y 4 pulgadas de profundidad; sellos más profundos pueden retener sólidos y no son estándar."},
  {id:238, q:"El 'vertedero' (weir) de un sifón es:", opts:["El tapón del registro","La parte superior del codo de salida donde el agua se vierte al brazo del sifón","La abertura de la ventilación","La entrada del sifón desde el mueble"], re:"El vertedero es la cresta sobre la cual el agua sale del sifón hacia el brazo; el sello se mide desde el codo (dip) hasta el vertedero."},
  {id:239, q:"Una coladera de piso de uso poco frecuente puede perder su sello por evaporación; esto se previene comúnmente con:", opts:["Una pendiente más profunda","Una ventilación más grande","Un cebador de sifón que agrega agua periódicamente","Un segundo sifón"], re:"Un cebador de sifón aporta una pequeña cantidad de agua al sifón para reponer la evaporación y mantener el sello intacto."},
  {id:240, q:"El sifón más común usado en muebles residenciales es el:", opts:["Sifón de campana","Sifón en S","Sifón de tambor","Sifón en P"], re:"El sifón en P, con su brazo horizontal hacia una ventilación, es el sifón de mueble aprobado estándar."},
  {id:241, q:"La pérdida del sello de un sifón es peligrosa principalmente porque permite:", opts:["Que el gas de cloaca entre al edificio","Mayor presión de agua","Retorno de agua potable","Golpe de ariete"], re:"Si se pierde el sello, los gases de cloaca (que pueden ser tóxicos e inflamables) pasan por el sifón vacío al espacio ocupado."},
  {id:242, q:"Un sifón puede perder su sello por autosifonaje, que es:", opts:["El congelamiento del agua en el sifón","La descarga del mueble que arrastra tras de sí el agua del sello","La evaporación a lo largo de meses","El viento sobre la ventilación"], re:"El autosifonaje ocurre cuando la propia descarga del mueble crea succión que extrae el agua del sello de un sifón sin ventilar."},
  {id:243, q:"Un sello de sifón también puede perderse por contrapresión, que es causada por:", opts:["Demasiada pendiente","La falta de un registro","Presión positiva en el desagüe que expulsa el sello hacia el mueble","El clima frío"], re:"La presión positiva que sube por la columna puede empujar el agua del sello fuera del sifón hacia el mueble, rompiendo el sello."},
  {id:244, q:"Cada mueble, salvo los de sifón integral, debe tener:", opts:["Un sifón compartido con el siguiente mueble","Dos sifones","Ningún sifón","Su propio sifón separado"], re:"Cada mueble de plomería debe sifonarse por separado (salvo que su sifón sea integral), de modo que el gas de cloaca quede bloqueado en cada mueble."},
  {id:245, q:"Un inodoro no necesita un sifón añadido por separado porque:", opts:["Tiene un sifón integral incorporado en el mueble","Usa un espacio de aire","Drena a un sifón de tambor","Se ventila de otra manera"], re:"Un inodoro tiene un sifón moldeado en la cerámica, por eso no se instala un sifón externo adicional."},
  {id:246, q:"La distancia desde el vertedero del sifón hasta el codo (dip) determina:", opts:["La longitud del brazo del sifón","La profundidad del sello del sifón","El diámetro de la ventilación","La pendiente del desagüe"], re:"La profundidad del sello es la distancia vertical entre el codo y el vertedero; debe ser de al menos 2 pulgadas."},
  {id:247, q:"Un material de sifón como el ABS o el latón cromado debe ser:", opts:["Más grande que la salida del mueble por 2 pulgadas","Relleno de arena","De interior liso y resistente a la corrosión","Hecho de plomo"], re:"Los materiales de sifón aprobados son de interior liso y resisten la corrosión para que el sello se conserve y el residuo no se atore en superficies ásperas."},
  {id:248, q:"Un sifón en P estándar debe instalarse de modo que el sifón quede:", opts:["Inclinado de modo que drene el sello","Solo dentro de la cavidad del muro","Por encima del borde de rebose","Nivelado y bajo el mueble, con el sello intacto"], re:"El sifón se coloca nivelado bajo el mueble para que retenga un sello completo de 2 pulgadas y el brazo pueda inclinarse hacia la ventilación y drenar."},
  {id:249, q:"Un sifón en S está prohibido principalmente porque:", opts:["Tiende a autosifonarse y perder su sello","No puede conectarse a un mueble","Es demasiado grande para cualquier desagüe","Es demasiado caro"], re:"Un sifón en S descarga directo hacia abajo, lo que autosifona el agua del sello; en su lugar se requiere un sifón en P ventilado."},
  {id:250, q:"Un sifón de campana no se permite porque:", opts:["Tiene un sello demasiado profundo","Pierde su sello fácilmente y es difícil de limpiar y mantener","Es solo para inodoros","No requiere ventilación"], re:"Los sifones de campana pierden su sello con facilidad y sus partes removibles se pierden o tapan fácilmente, por eso están prohibidos."},
  {id:251, q:"Un sifón de tambor generalmente está prohibido o desaconsejado porque:", opts:["Es demasiado pequeño para usarse","Se autolimpia bien","Acumula desechos y es difícil de limpiar y ventilar adecuadamente","No tiene sello"], re:"Los sifones de tambor tienden a acumular sólidos y son difíciles de limpiar y ventilar, por eso los códigos modernos los restringen o prohíben."},
  {id:252, q:"El doble sifón en un solo mueble está prohibido porque el aire atrapado entre los dos sifones:", opts:["Acelera el flujo","Aumenta la profundidad del sello","Mejora el sello","No tiene salida de ventilación y causa drenaje lento y pérdida del sello"], re:"El aire encerrado entre dos sifones no puede escapar, por lo que el drenaje es lento y los sellos tienden a ser arrastrados o expulsados."},
  {id:253, q:"Un sifón que depende de partes móviles o de una partición para retener su sello está:", opts:["Generalmente prohibido","Requerido para coladeras de piso","Igual que un sifón en P","Preferido para fregaderos"], re:"Los sifones que dependen de partes móviles, particiones interiores o mecanismos ocultos están prohibidos porque el sello no es confiable."},
  {id:254, q:"El brazo del sifón es la parte de tubo que va desde el:", opts:["Terminal de ventilación al techo","Vertedero del sifón a la conexión de la ventilación","Borde del mueble al sifón","Registro a la cloaca"], re:"El brazo del sifón se extiende desde la salida del sifón (vertedero) hasta el punto donde la ventilación se conecta al desagüe."},
  {id:255, q:"Para un brazo de sifón de 1-1/4 pulgada, la longitud desarrollada máxima hasta su ventilación es de unas:", opts:["Sin límite","6 pulgadas","30 pulgadas","10 pies"], re:"Un brazo de sifón de 1-1/4 pulgada puede tener hasta unas 30 pulgadas (2-1/2 pies) de largo antes de que el sifón corra riesgo de autosifonaje."},
  {id:256, q:"Para un brazo de sifón de 1-1/2 pulgada, la longitud máxima hasta la ventilación es de unas:", opts:["8 pies","Sin límite","18 pulgadas","42 pulgadas"], re:"Un brazo de sifón de 1-1/2 pulgada se limita a unas 42 pulgadas (3-1/2 pies) de longitud desarrollada hasta la ventilación."},
  {id:257, q:"Para un brazo de sifón de 2 pulgadas, la longitud desarrollada máxima hasta la ventilación es de unos:", opts:["5 pies","20 pies","Sin límite","2 pies"], re:"Un brazo de sifón de 2 pulgadas puede extenderse unos 5 pies hasta su ventilación según la tabla de longitud de brazo de sifón."},
  {id:258, q:"Para un brazo de sifón de 3 pulgadas, la longitud desarrollada máxima hasta la ventilación es de unos:", opts:["3 pies","6 pies","30 pies","Sin límite"], re:"Un brazo de sifón de 3 pulgadas se limita generalmente a unos 6 pies de longitud desarrollada hasta la ventilación."},
  {id:259, q:"El brazo del sifón hacia su ventilación, en ningún caso, debe ser más corto que:", opts:["La mitad del sello del sifón","El ancho del mueble","Dos veces el diámetro del brazo del sifón","La altura de la ventilación"], re:"El brazo del sifón debe medir al menos dos diámetros de tubo para que la conexión de ventilación no quede inundada por la descarga del sifón."},
  {id:260, q:"Limitar la longitud del brazo del sifón protege al sifón principalmente contra:", opts:["El golpe de ariete","La alta presión de suministro","El congelamiento","El autosifonaje que vaciaría el sello"], re:"Si el brazo del sifón es demasiado largo, la descarga en caída puede sifonar el sello; el límite de longitud previene este autosifonaje."},
  {id:261, q:"La ventilación de un sifón debe conectarse al brazo del sifón:", opts:["En o por encima del nivel del vertedero del sifón","Solo en el borde del mueble","En cualquier punto del desagüe del edificio","Por debajo del vertedero del sifón"], re:"La ventilación se conecta en o por encima del vertedero para que el brazo del sifón no se llene e inunde la abertura de la ventilación con agua residual."},
  {id:262, q:"El brazo del sifón no debe tener una caída vertical mayor que su propio diámetro antes de llegar a la ventilación, para evitar:", opts:["Un sifón más grande","Recrear el efecto de autosifonaje de un sifón en S","Una ventilación más grande","Un segundo sifón"], re:"El exceso de caída vertical en el brazo del sifón crea una condición de sifón en S que puede sifonar el sello, por eso la caída se limita."},
  {id:263, q:"Conectar dos muebles para que compartan un solo sifón (salvo un conjunto aprobado) está:", opts:["Permitido solo para inodoros","Siempre requerido","Generalmente prohibido","Recomendado para tinas"], re:"Los muebles deben sifonarse individualmente salvo combinaciones aprobadas, por eso compartir un solo sifón generalmente no se permite."},
  {id:264, q:"El propósito principal del sistema de ventilación es:", opts:["Suministrar agua a los muebles","Calentar el edificio","Llevar el residuo a la cloaca","Admitir aire para proteger los sellos de los sifones e igualar la presión en los desagües"], re:"Las ventilaciones admiten aire para que el drenaje fluya suavemente y los sellos de los sifones no se sifoneen ni se expulsen por cambios de presión."},
  {id:265, q:"Una ventilación individual (de respaldo) sirve a:", opts:["El sifón de un solo mueble","Solo el desagüe del edificio","Solo el calentador de agua","Cada mueble del edificio"], re:"Una ventilación individual se conecta y protege el sifón de un mueble, ventilando ese mueble por sí solo."},
  {id:266, q:"Una ventilación común es una sola ventilación que sirve a:", opts:["Ningún mueble","Dos muebles conectados al mismo nivel","Ocho o más inodoros","Todo el edificio"], re:"Una ventilación común sirve a dos muebles cuyos desagües se conectan al mismo nivel, ventilando ambos por un solo tubo."},
  {id:267, q:"Una ventilación húmeda es un tubo que funciona como:", opts:["Un registro de limpieza","Solo una ventilación","A la vez un desagüe para un mueble y una ventilación para otro","Una línea de suministro de agua"], re:"Una ventilación húmeda lleva el desagüe de un mueble mientras también sirve como ventilación de otro mueble del grupo."},
  {id:268, q:"Una ventilación de circuito se usa para ventilar:", opts:["Solo el techo","Un calentador de agua","Un solo lavabo","Una batería de muebles en una derivación horizontal mediante una sola ventilación"], re:"Una ventilación de circuito sirve a una hilera (batería) de muebles en una derivación horizontal, ventilándolos con una sola ventilación antes del último mueble."},
  {id:269, q:"Una columna de ventilación (vent stack) es un tubo de ventilación vertical instalado principalmente para:", opts:["Proporcionar circulación de aire hacia y desde el sistema de drenaje","Suministrar agua fría","Mantener el sello del sifón","Drenar el residuo"], re:"Una columna de ventilación es una ventilación vertical que hace circular el aire por el sistema de drenaje, aliviando a menudo la columna en varios pisos."},
  {id:270, q:"Una ventilación de columna (stack vent) es:", opts:["Un tubo de agua separado","La prolongación de una columna de aguas negras o residuales por encima de la derivación más alta","Una trampa de grasa","Un cebador de sifón"], re:"Una ventilación de columna es la prolongación seca de una columna de aguas negras o residuales por encima del desagüe horizontal más alto conectado a esa columna."},
  {id:271, q:"Los tubos de ventilación deben inclinarse y conectarse de modo que:", opts:["Suban cuesta arriba hacia el techo","Retengan agua estancada","Drenen cualquier condensado de regreso al desagüe por gravedad","Se inclinen en sentido contrario a la columna"], re:"Las ventilaciones se inclinan para que la humedad drene de regreso al tubo de desagüe y no se acumule y bloquee el paso de aire."},
  {id:272, q:"Donde una ventilación termina a través de un techo, debe extenderse por encima del techo al menos unas:", opts:["2 pulgadas","3 pies","10 pies","6 pulgadas"], re:"Una terminal de ventilación debe elevarse al menos 6 pulgadas sobre el techo para que la nieve o el encharcamiento no la bloqueen."},
  {id:273, q:"Una terminal de ventilación debe mantenerse alejada de una ventana practicable o toma de aire por lo menos:", opts:["10 pies en horizontal (o terminar 3 pies por encima)","100 pies","6 pulgadas","1 pie"], re:"Para mantener el gas de cloaca fuera del edificio, una ventilación debe estar al menos a 10 pies de una abertura o terminar 3 pies por encima de ella."},
  {id:274, q:"El tamaño mínimo para la mayoría de las ventilaciones individuales es:", opts:["1/2 pulgada","1-1/4 pulgada","3 pulgadas","4 pulgadas"], re:"Las ventilaciones generalmente no son menores de 1-1/4 pulgada, y una ventilación debe ser al menos la mitad del diámetro del desagüe que sirve."},
  {id:275, q:"El diámetro de una ventilación generalmente debe ser al menos:", opts:["Un décimo del diámetro del desagüe","El doble del diámetro del desagüe","La mitad del diámetro del desagüe que sirve","Igual que la tubería principal de agua"], re:"Una ventilación no debe ser menor que la mitad del diámetro del desagüe que sirve, con un tamaño mínimo, para admitir suficiente aire."},
  {id:276, q:"Una válvula de admisión de aire (AAV), donde se permite, funciona al:", opts:["Bombear agua","Reemplazar el sifón","Liberar gas de cloaca a la habitación","Abrirse para admitir aire con presión negativa y sellar contra la presión positiva"], re:"Una AAV se abre para dejar entrar aire cuando el desagüe genera vacío y se cierra bajo presión positiva para que el gas no pueda escapar."},
  {id:277, q:"Una ventilación de alivio se provee principalmente para:", opts:["Aliviar la presión entre la columna de drenaje y una derivación horizontal","Suministrar agua caliente","Atrapar sólidos","Drenar los muebles"], re:"Una ventilación de alivio ofrece una vía de aire adicional para que las diferencias de presión en la columna no afecten los sellos de los sifones de la derivación."},
  {id:278, q:"La tubería de ventilación que corre horizontalmente debe mantenerse por encima del:", opts:["Línea del techo","Borde de rebose de los muebles que sirve","Solo el desagüe del edificio","Medidor de agua"], re:"Los tramos horizontales de ventilación deben mantenerse por encima del borde de rebose de los muebles para que el agua residual no pueda entrar a la ventilación."},
  {id:279, q:"Un mueble que no está ventilado adecuadamente es más propenso a sufrir de:", opts:["Exceso de pendiente","Alta presión de agua","Drenaje lento y con borboteo y un sello de sifón sifonado","Tubos congelados"], re:"Sin ventilación, el sifón puede sifonarse y el aire no puede entrar, por lo que el mueble drena lento y borbotea al arrastrarse el sello."},
  {id:280, q:"En un grupo de baño con ventilación húmeda, la ventilación húmeda suele sobredimensionarse para que pueda:", opts:["Retener más sello de sifón","Reemplazar el desagüe del edificio","Servir como registro de limpieza","Llevar el desagüe y aún pasar aire para ventilar los demás muebles"], re:"La ventilación húmeda se agranda para que pueda llevar la descarga de un mueble y aún dejar una vía de aire para ventilar los demás."},
  {id:281, q:"Un registro de limpieza se provee en el sistema de drenaje para:", opts:["Dar acceso para destapar obstrucciones sin cortar el tubo","Reducir el tamaño del tubo","Mantener el sello del sifón","Ventilar la línea"], re:"Un registro da acceso para que un desagüe se pueda varillar o destapar para quitar una obstrucción sin desarmar el tubo."},
  {id:282, q:"En un desagüe horizontal largo, los registros de limpieza generalmente se requieren a intervalos de no más de:", opts:["10 pies","100 pies de longitud desarrollada","500 pies","1,000 pies"], re:"Se requiere un registro por cada 100 pies (o fracción) de longitud desarrollada en un desagüe horizontal para poder alcanzar cualquier punto."},
  {id:283, q:"También se requiere un registro de limpieza donde el cambio de dirección agregado en un tramo de desagüe excede unos:", opts:["45 grados","90 grados","135 grados","360 grados"], re:"Se requiere un registro adicional donde los cambios de dirección horizontales suman más de 135 grados, ya que las curvas dificultan el varillado."},
  {id:284, q:"Debe instalarse un registro de limpieza en el extremo superior de:", opts:["La columna de ventilación","La línea de gas","La línea de suministro de agua","Cada tramo de tubo de drenaje horizontal"], re:"Cada tramo de desagüe horizontal necesita un registro en su extremo superior para que una sonda pueda correr aguas abajo por toda la línea."},
  {id:285, q:"Los registros de limpieza deben instalarse de modo que estén:", opts:["Fácilmente accesibles para limpiar el desagüe","Siempre en el techo","Dentro del sello del sifón","Enterrados y sellados permanentemente"], re:"Un registro es inútil si no se puede alcanzar, por eso debe permanecer fácilmente accesible para dar servicio al desagüe."},
  {id:286, q:"Un registro de limpieza generalmente puede omitirse en un desagüe horizontal más corto que:", opts:["No existe excepción","5 pies (salvo que sirva a fregaderos o mingitorios)","50 pies","100 pies"], re:"Los desagües horizontales muy cortos, de menos de 5 pies, pueden omitir un registro, salvo donde sirven a fregaderos o mingitorios."},
  {id:287, q:"Una trampa de grasa (interceptor de grasa) se instala para:", opts:["Aumentar la presión del agua","Agregar agua al sifón","Mantener grasas, aceites y grasa fuera de la cloaca del edificio","Ventilar la cocina"], re:"Una trampa de grasa separa y retiene grasas, aceites y grasa para que no entren ni tapen el sistema de cloaca."},
  {id:288, q:"Una trampa de grasa se requiere con mayor frecuencia en el desagüe de:", opts:["Un aspersor de jardín","Un desagüe de techo","Una tina residencial","Los fregaderos y el lavavajillas de una cocina comercial"], re:"Las cocinas comerciales descargan grandes cargas de grasa, por eso sus muebles de lavado drenan a través de una trampa de grasa."},
  {id:289, q:"Un interceptor de grasa hidromecánico generalmente tiene un caudal nominal no menor de unos:", opts:["20 gpm","200 gpm","2,000 gpm","2 gpm"], re:"Los interceptores de grasa hidromecánicos con clasificación de código típicamente parten de unos 20 gpm de capacidad de caudal."},
  {id:290, q:"A un inodoro generalmente no se le permite descargar a través de una trampa de grasa porque el interceptor está destinado solo a:", opts:["Aguas residuales sanitarias de los inodoros","Residuo grasoso, no aguas negras humanas","Agua pluvial","Aire de ventilación"], re:"Las trampas de grasa manejan el residuo grasoso de los muebles; el residuo del inodoro (aguas negras) se mantiene fuera para que no ensucie el interceptor."},
  {id:291, q:"Un interceptor de arena o aceite se usa para mantener:", opts:["El agua en el sifón","Solo grasa","Arena, aceite u otros materiales pesados fuera del sistema de drenaje","El gas de ventilación en el tubo"], re:"Los interceptores de arena y aceite separan sólidos pesados y productos del petróleo (como en talleres y lavados de autos) antes del desagüe."},
  {id:292, q:"El desagüe del edificio es la tubería de drenaje horizontal más baja que:", opts:["Suministra agua","Ventila las columnas","Corre por el techo","Recibe la descarga de todos los desagües del edificio y la lleva a la cloaca del edificio"], re:"El desagüe del edificio es la parte más baja del sistema de drenaje dentro del edificio, que recoge todo el residuo y lo conduce afuera a la cloaca."},
  {id:293, q:"El desagüe del edificio típicamente se convierte en cloaca del edificio en un punto a unos:", opts:["2 pies fuera del muro del edificio","En la ventilación del techo","En el medidor de agua","En el sifón del mueble"], re:"Por definición el desagüe del edificio se extiende hasta unos 2 pies fuera del muro del edificio, donde se convierte en la cloaca del edificio."},
  {id:294, q:"La cloaca del edificio lleva el residuo desde el desagüe del edificio hasta:", opts:["El calentador de agua","La cloaca pública o un sistema de disposición privado aprobado","El desagüe de techo","La terminal de ventilación"], re:"La cloaca del edificio conduce el residuo del edificio desde el desagüe del edificio hasta la cloaca pública o un sistema de disposición aprobado en sitio."},
  {id:295, q:"El agua de lluvia (pluvial) y los desagües de techo generalmente se:", opts:["Conectan a la ventilación","Descargan a la cloaca sanitaria junto con los inodoros","Mantienen separados del sistema de drenaje sanitario","Encaminan a través de la trampa de grasa"], re:"El agua pluvial normalmente se mantiene fuera del sistema sanitario y se maneja con un sistema de drenaje pluvial separado."},
  {id:296, q:"Un registro de limpieza en la unión del desagüe del edificio y la cloaca del edificio le permite a un técnico de servicio:", opts:["Agregar un sifón","Aumentar la pendiente","Ventilar la cloaca","Varillar la cloaca del edificio hacia la calle"], re:"Un registro cerca de la unión edificio/cloaca da acceso para varillar la cloaca del edificio hacia la red pública."},
  {id:297, q:"Un sifón de edificio (sifón de casa), donde se usa, está destinado a:", opts:["Proporcionar un solo sello entre el desagüe del edificio y la cloaca pública","Bombear el residuo cuesta arriba","Reemplazar los sifones de los muebles","Ventilar el edificio"], re:"Un sifón de edificio coloca un solo sello en el desagüe del edificio para bloquear los gases de cloaca de la red; muchos códigos ahora lo restringen a favor de sifones de mueble y ventilación."},
  {id:298, q:"El tubo de drenaje subterráneo del edificio generalmente debe enterrarse bajo la superficie al menos unas:", opts:["1 pulgada","12 pulgadas (1 pie)","6 pies","Sin mínimo"], re:"La tubería de drenaje bajo o cerca de un edificio generalmente se mantiene al menos a unas 12 pulgadas bajo el nivel del suelo para protegerla de daños."},
  {id:299, q:"El tamaño mínimo para un desagüe o cloaca de edificio que sirve a uno o más inodoros es:", opts:["1-1/2 pulgada","2 pulgadas","3 pulgadas","Sin mínimo"], re:"Como un inodoro requiere un desagüe de 3 pulgadas, todo desagüe o cloaca de edificio que lleve un inodoro debe ser de al menos 3 pulgadas."},
  {id:300, q:"Antes de rellenar una cloaca de edificio subterránea, el instalador debe:", opts:["Quitar los registros de limpieza","Conectarla a la ventilación","Omitir toda prueba","Probar la línea en busca de fugas y confirmar la pendiente adecuada"], re:"La cloaca se prueba de estanqueidad y se verifica que tenga una pendiente continua antes de rellenar, ya que los defectos son difíciles de corregir una vez enterrados."},
  {id:301, q:"Un inodoro con fluxómetro (válvula de descarga) se diferencia de uno con tanque en que:", opts:["Se conecta directo al suministro y dosifica el agua por una válvula, sin tanque de almacenamiento","Siempre usa más de 5 galones por descarga","Almacena el agua de descarga en un tanque por gravedad","No puede usarse en edificios comerciales"], re:"El fluxómetro se conecta directo al suministro de agua y libera un chorro dosificado por una válvula, por eso no necesita tanque y es común en baños comerciales."},
  {id:302, q:"Una válvula de fluxómetro requiere que la tubería de suministro provea:", opts:["Caudal muy bajo durante mucho tiempo","Ninguna presión mínima","Caudal-presión suficiente para operar la válvula rápidamente","Solo gravedad de un tanque en la azotea"], re:"Como el fluxómetro descarga un chorro corto y de alto caudal, el ramal debe dar suficiente caudal-presión para que la válvula funcione; un tubo chico la priva."},
  {id:303, q:"Un inodoro con tanque por gravedad genera su descarga mediante:", opts:["Una bomba en la taza","Un solenoide eléctrico","Solo aire comprimido","La liberación del peso y volumen del agua almacenada en el tanque"], re:"El inodoro por gravedad depende de la altura y el volumen de agua que cae del tanque para sifonar la taza, por eso los de tanque dominan en viviendas."},
  {id:304, q:"Un inodoro de doble descarga está diseñado para:", opts:["Ofrecer una descarga reducida para líquidos y una completa para sólidos","Descargar solo con agua caliente","Usar dos suministros de agua separados","Requerir una válvula de fluxómetro"], re:"Los de doble descarga dan una descarga parcial para líquidos y una completa para sólidos, ahorrando agua en las descargas ligeras más frecuentes."},
  {id:305, q:"El volumen máximo federal de descarga para un inodoro estándar nuevo es:", opts:["3.5 galones por descarga","5.0 galones por descarga","1.6 galones por descarga","2.5 galones por descarga"], re:"La norma nacional limita un inodoro estándar a 1.6 galones por descarga; los modelos de alta eficiencia usan aún menos."},
  {id:306, q:"Un inodoro de alta eficiencia (con etiqueta WaterSense) usa no más de:", opts:["1.6 galones por descarga","2.0 galones por descarga","1.28 galones por descarga","3.5 galones por descarga"], re:"Los inodoros WaterSense se limitan a 1.28 galones por descarga, cerca de un 20% de ahorro frente al estándar federal de 1.6 gpf."},
  {id:307, q:"En California, el caudal máximo permitido para una regadera (ducha) residencial es:", opts:["1.8 galones por minuto","2.5 galones por minuto","3.0 galones por minuto","5.0 galones por minuto"], re:"California limita las regaderas a 1.8 galones por minuto; cuando varias comparten una válvula, su caudal combinado no puede exceder esa cifra."},
  {id:308, q:"Cuando varias regaderas son servidas por una sola válvula de control, el caudal combinado debe:", opts:["Duplicarse por cada regadera","Ser ilimitado","No exceder el límite de una sola regadera a la presión de prueba","Medirse solo en el medidor"], re:"California trata las regaderas de una válvula como un conjunto; juntas no pueden exceder 1.8 gpm a 80 psi, así que agregar regaderas no evade el límite."},
  {id:309, q:"Una válvula de descarga de mingitorio en un baño público suele ser de tipo:", opts:["Tanque por gravedad","Cubeta vertida a mano","Solo bomba de pie","Fluxómetro (válvula de descarga)"], re:"Los mingitorios suelen servirse con válvulas de fluxómetro conectadas directo al suministro, la misma familia de válvula de los inodoros comerciales."},
  {id:310, q:"Un diseño de taza 'sifón-jet' se refiere a un inodoro que:", opts:["Usa un chorro de agua para iniciar un sifón y limpiar la taza","No tiene trampa","Drena solo por presión de aire","No puede retener un sello de agua"], re:"El sifón-jet dirige agua por un chorro en el sifón para cebarlo, dando una descarga fuerte y silenciosa y una gran superficie de agua."},
  {id:311, q:"Un inodoro montado en el piso se sella a la brida del desagüe con:", opts:["Cinta de silicón","Cemento solvente","Solo masilla de plomero","Un anillo de cera (o empaque aprobado)"], re:"Un anillo de cera o empaque sin cera listado sella el cuerno del inodoro a la brida para que ni desechos ni gases de cloaca escapen en el piso."},
  {id:312, q:"El flotador de llenado (ballcock) dentro del tanque de un inodoro por gravedad se encarga de:", opts:["Rellenar el tanque y la taza después de una descarga","Calentar el agua","Ventear gases de cloaca","Cerrar la llave de paso del edificio"], re:"La válvula de llenado rellena el tanque a su nivel y realimenta la taza tras cada descarga para que la trampa vuelva a sellar y el tanque quede listo."},
  {id:313, q:"El tubo de rebose en el tanque de un inodoro existe para:", opts:["Acelerar la descarga","Reemplazar el sapo (flapper)","Aumentar la presión del tanque","Enviar el agua excedente a la taza en vez de al piso"], re:"Si la válvula de llenado no cierra, el tubo de rebose lleva el agua extra hacia la taza y al desagüe en lugar de desbordar el tanque."},
  {id:314, q:"Un inodoro de presión asistida mejora la descarga mediante:", opts:["Usar un tanque en la azotea","Eliminar la trampa","Usar la presión del agua del edificio para comprimir aire que impulsa la descarga","Agregar una bomba de recirculación"], re:"Un recipiente de presión asistida dentro del tanque usa la presión de la línea para comprimir aire atrapado, que luego expulsa el agua con más energía para una descarga más fuerte."},
  {id:315, q:"El sapo (flapper, sello de la válvula de descarga) en el fondo de un tanque por gravedad:", opts:["Calienta el agua","Ventea la taza","Reduce la presión de suministro","Se abre para soltar el agua del tanque y luego vuelve a asentarse para retenerla"], re:"Al subir la palanca, el sapo se levanta para vaciar el tanque; cuando el tanque se vacía el sapo baja y sella para que el tanque vuelva a llenarse."},
  {id:316, q:"California exige que el eje (línea central) de un inodoro esté al menos a qué distancia de una pared lateral u obstrucción?", opts:["15 pulgadas","8 pulgadas","21 pulgadas","30 pulgadas"], re:"El código exige no menos de 15 pulgadas desde el eje del inodoro a cualquier pared lateral u obstrucción para que el aparato pueda usarse cómodamente."},
  {id:317, q:"El espacio libre mínimo requerido frente a un inodoro es:", opts:["12 pulgadas","6 pulgadas","36 pulgadas","24 pulgadas"], re:"Debe proveerse al menos 24 pulgadas de espacio libre frente a un inodoro para acceso y uso."},
  {id:318, q:"Dos inodoros adyacentes deben tener sus ejes separados por al menos:", opts:["15 pulgadas","18 pulgadas","30 pulgadas","24 pulgadas"], re:"La separación de eje a eje entre dos inodoros (o un inodoro y un bidé) debe ser de al menos 30 pulgadas."},
  {id:319, q:"El desagüe y brazo de trampa de un inodoro residencial estándar debe ser de al menos:", opts:["1-1/2 pulgada","2 pulgadas","2-1/2 pulgadas","3 pulgadas"], re:"Un inodoro requiere un desagüe y brazo de trampa de 3 pulgadas para llevar su descarga, mayor que los ramales que sirven lavabos y tinas."},
  {id:320, q:"El tamaño mínimo de trampa y desagüe para un lavabo (de baño) es:", opts:["1-1/4 pulgada","1-1/2 pulgada","2 pulgadas","3 pulgadas"], re:"Un lavabo puede usar una trampa y desagüe de 1-1/4 pulgada, la trampa de aparato más pequeña que permite el código."},
  {id:321, q:"El tamaño mínimo de trampa para un fregadero de cocina es:", opts:["1-1/4 pulgada","3 pulgadas","2 pulgadas","1-1/2 pulgada"], re:"Un fregadero de cocina requiere al menos una trampa de 1-1/2 pulgada, mayor que un lavabo porque lleva más residuos y más grasosos."},
  {id:322, q:"Una tina de baño se sirve con una trampa de al menos:", opts:["1-1/4 pulgada","2 pulgadas","1-1/2 pulgada","3 pulgadas"], re:"Una tina usa una trampa mínima de 1-1/2 pulgada, el mismo mínimo que un fregadero de cocina."},
  {id:323, q:"Un compartimento de regadera debe tener un área interior terminada mínima de, y contener un círculo de 30 pulgadas, de:", opts:["1024 pulgadas cuadradas","576 pulgadas cuadradas","720 pulgadas cuadradas","2048 pulgadas cuadradas"], re:"Una regadera debe encerrar al menos 1024 pulgadas cuadradas de interior terminado y poder contener un círculo de 30 pulgadas de diámetro."},
  {id:324, q:"El desagüe de una regadera y su trampa deben ser de al menos:", opts:["1-1/4 pulgada","1-1/2 pulgada","2 pulgadas","4 pulgadas"], re:"Una regadera requiere un desagüe y trampa mínimos de 2 pulgadas para llevar su caudal sin retornos."},
  {id:325, q:"Las dimensiones requeridas de una regadera deben mantenerse desde el desagüe hasta una altura de al menos:", opts:["48 pulgadas","60 pulgadas","70 pulgadas","84 pulgadas"], re:"El interior libre de la regadera debe mantenerse a al menos 70 pulgadas sobre el desagüe, dejando sobresalir solo la válvula, la regadera, jaboneras y barras de apoyo."},
  {id:326, q:"La longitud desarrollada de un brazo de trampa (del vertedero de la trampa al venteo) se limita principalmente para evitar:", opts:["Que el sello de la trampa sea sifonado","Que el agua se congele","Alta presión de agua","Solo ruido excesivo"], re:"Si el brazo de trampa es muy largo, la caída puede sifonar la trampa hasta secarla; el código limita su longitud para que el venteo proteja el sello."},
  {id:327, q:"Un brazo de trampa horizontal nunca debe medir menos de cuántos diámetros de tubo desde el vertedero de la trampa al venteo?", opts:["Uno","Diez","Cinco","Dos"], re:"El brazo de trampa debe correr al menos dos diámetros de tubo desde el vertedero al venteo para que la abertura de venteo no quede por debajo de la descarga de la trampa."},
  {id:328, q:"Un lavabo residencial normalmente necesita espacio libre al frente de al menos:", opts:["12 pulgadas","30 pulgadas","24 pulgadas","6 pulgadas"], re:"Como un inodoro, a un lavabo se le dan al menos 24 pulgadas de espacio libre al frente para poder acercarse y usarlo."},
  {id:329, q:"Las llaves de paso (angulares) de suministro en un fregadero o inodoro se instalan principalmente para:", opts:["Reducir la presión de la casa","Ventear el desagüe","Retener el sello de la trampa","Aislar ese aparato para reparación sin cerrar toda la casa"], re:"Una llave angular accesible bajo cada aparato permite cerrarlo para servicio mientras el resto del edificio conserva el agua."},
  {id:330, q:"Las dimensiones de plomería en bruto (rough-in) son las ubicaciones de las salidas de suministro y desagüe fijadas:", opts:["Antes de cerrar muros y acabados","Después de terminar los muros","Solo en la inspección final","Después de colocar los aparatos"], re:"El rough-in fija la altura y posición de las salidas de tubo con el muro abierto, para que los aparatos terminados queden en el lugar correcto."},
  {id:331, q:"Una trampa de coladera de piso pierde su sello con mayor probabilidad por:", opts:["Sobrepresión","Pendiente excesiva","Venteo demasiado pequeño","Evaporación cuando la coladera se usa poco"], re:"Una coladera de piso poco usada puede secarse por evaporación y dejar entrar gases de cloaca, por eso requieren cebadores o atención."},
  {id:332, q:"Un cebador de trampa (trap primer) se provee para:", opts:["Agregar agua a la trampa de una coladera de piso para conservar su sello","Aumentar el volumen de descarga","Reducir la presión de gas","Ventear la columna"], re:"Un cebador alimenta una pequeña cantidad de agua a la trampa de una coladera de piso para que el sello no se evapore y deje entrar gases de cloaca."},
  {id:333, q:"La válvula de alivio de temperatura y presión (T y P) de un calentador de agua protege contra:", opts:["Baja presión de suministro","Retroflujo hacia la red municipal","Temperatura y presión excesivas dentro del tanque","Sarro por agua dura"], re:"La válvula T y P abre si la temperatura o la presión del tanque suben demasiado, aliviándolo antes de que el tanque pueda romperse o explotar."},
  {id:334, q:"El tubo de descarga de una válvula de alivio T y P debe:", opts:["Ser más pequeño que la salida de la válvula","Drenar por gravedad sin válvula ni trampa","Conectarse directo al drenaje del edificio","Subir hacia un punto alto"], re:"La línea de alivio debe ser de tamaño completo, correr cuesta abajo por gravedad, sin llave ni trampa, y terminar en un punto aprobado para poder descargar siempre."},
  {id:335, q:"El tubo de descarga de una válvula T y P debe ser del mismo tamaño que, o no menor que:", opts:["1/4 pulgada","El conducto de humos (flue)","La entrada de agua fría","La salida de la válvula"], re:"El tubo de descarga debe ser al menos del tamaño de la salida de la válvula de alivio en toda su longitud para no restringir el flujo de alivio."},
  {id:336, q:"Un tubo de descarga T y P que termina en interiores debe terminar a no más de qué altura sobre el piso o receptor?", opts:["6 pulgadas","2 pulgadas","12 pulgadas","24 pulgadas"], re:"Una descarga de alivio interior debe terminar a no más de 6 pulgadas sobre el piso o receptor (y al menos dos diámetros de tubo), para que una descarga sea visible pero no escalde."},
  {id:337, q:"El extremo de un tubo de descarga T y P debe:", opts:["Estar roscado para una tapa","Descargar hacia arriba","No tener conexión roscada","Tener una llave para control"], re:"El extremo terminal no debe estar roscado, para que nadie pueda taparlo, obturarlo o ponerle una llave y anular la vía de alivio."},
  {id:338, q:"Una llave de paso u otra restricción en la línea de descarga de alivio T y P es:", opts:["Exigida por el código","Recomendada para control","Permitida solo en exteriores","Prohibida"], re:"No se permite ninguna llave, te ni reductor entre la válvula de alivio y el extremo abierto, porque cualquier restricción podría bloquear la descarga de emergencia."},
  {id:339, q:"Un calentador de agua colocado donde una fuga podría causar daño (como un ático o piso superior) requiere:", opts:["Una charola de drenaje conectada a un punto aprobado","Una segunda válvula de alivio","Un conducto de humos más grande","Ninguna provisión especial"], re:"Una charola resistente a la corrosión con su propio drenaje a un punto aprobado capta la fuga y protege la estructura bajo el calentador."},
  {id:340, q:"La línea de drenaje de la charola de un calentador de agua debe ser de al menos:", opts:["3/4 pulgada","1/2 pulgada","1-1/4 pulgada","2 pulgadas"], re:"El drenaje de la charola no debe ser menor de 3/4 de pulgada de diámetro y debe llevar la fuga a un punto aprobado."},
  {id:341, q:"Una llave de paso de paso completo de agua fría en un calentador debe ubicarse:", opts:["En la salida de agua caliente","En el conducto de humos","En la descarga de alivio","En el suministro de agua fría al calentador"], re:"Se requiere una llave de paso completo en la línea de suministro de agua fría al calentador para poder aislar la unidad y darle servicio."},
  {id:342, q:"¿Por qué se coloca la llave de paso en la entrada fría y no en la salida caliente de un calentador?", opts:["Para poder aislar y vaciar el tanque para servicio","Para elevar la temperatura de salida","Para reducir el tamaño del conducto de humos","Para eliminar la válvula de alivio"], re:"Cerrar la entrada fría aísla el tanque del suministro para poder vaciarlo y darle servicio; entonces el lado caliente queda sin alimentación."},
  {id:343, q:"Si una válvula T y P gotea o descarga repetidamente, la respuesta correcta es:", opts:["Tapar el tubo de descarga","Obturar la válvula","Encontrar y corregir la causa (exceso de temperatura o presión)","Quitar la válvula"], re:"Las descargas frecuentes señalan sobretemperatura o sobrepresión reales (a menudo expansión térmica); debe corregirse la causa, nunca obturar la válvula."},
  {id:344, q:"En un sistema de agua cerrado, la expansión térmica en el calentador se controla mejor con:", opts:["Quitar la válvula de alivio","Un conducto de humos más grande","Un tanque de expansión en el suministro de agua fría","Una segunda charola de drenaje"], re:"Con una válvula de retención o regulador que cierra el sistema, un tanque de expansión absorbe el aumento de presión por calentamiento para que la válvula de alivio no se vea forzada a gotear."},
  {id:345, q:"Una válvula de alivio T y P suele estar calibrada para abrir por temperatura a cerca de:", opts:["120 grados F","150 grados F","210 grados F","300 grados F"], re:"Una válvula T y P estándar se ajusta para aliviar a cerca de 210 grados F por temperatura (y comúnmente 150 psi por presión) para evitar que el agua se convierta en vapor."},
  {id:346, q:"En California, un calentador de agua residencial debe arriostrarse contra sismos con:", opts:["Sin correas","Una sola correa arriba","Una correa solo abajo","Al menos dos correas, en los tercios superior e inferior del tanque"], re:"California exige amarrar el tanque en sus tercios superior e inferior para que no se vuelque durante un sismo."},
  {id:347, q:"La correa sísmica inferior de un calentador debe mantenerse al menos a qué distancia sobre los controles?", opts:["4 pulgadas","1 pulgada","12 pulgadas","24 pulgadas"], re:"La correa inferior se coloca en el tercio inferior pero al menos 4 pulgadas sobre los controles de gas para no interferir con ellos."},
  {id:348, q:"Un calentador de agua a gas instalado en una cochera residencial generalmente debe tener su fuente de ignición (quemador) ubicada:", opts:["A nivel del piso","Exactamente 6 pulgadas sobre el piso","Bajo el piso","Al menos 18 pulgadas sobre el piso, salvo que esté listado FVIR"], re:"En una cochera el quemador debe estar al menos 18 pulgadas sobre el piso para que vapores inflamables más pesados que el aire no lo alcancen, salvo que el calentador sea resistente a la ignición de vapores inflamables (FVIR)."},
  {id:349, q:"Un calentador en la trayectoria de un vehículo en una cochera también requiere:", opts:["Un conducto de humos más alto","Protección contra impacto físico (como un poste o barrera)","Una válvula de alivio más grande","Una segunda charola"], re:"Donde un vehículo pudiera golpearlo, el calentador debe protegerse con una barrera o poste para que un impacto no lo dañe."},
  {id:350, q:"El aire de combustión para un calentador de agua a gas confinado normalmente se provee como:", opts:["Una abertura solo a media altura","Ninguna abertura","Dos aberturas, una cerca de la parte superior y otra cerca de la inferior del recinto","Una sola coladera de piso"], re:"El método tradicional da dos aberturas permanentes, una a no más de 12 pulgadas de la parte superior y otra a no más de 12 pulgadas de la inferior, para que el aire circule para la combustión."},
  {id:351, q:"Para dos aberturas que comunican directo con el exterior, cada abertura debe tener un área libre de al menos:", opts:["1 pulgada cuadrada por cada 1000 Btu/h","10 pulgadas cuadradas por cada 1000 Btu/h","1 pulgada cuadrada por cada 100 Btu/h","1 pulgada cuadrada por cada 4000 Btu/h"], re:"Cuando dos aberturas comunican directo con el exterior (o por ductos verticales), cada una debe ser de al menos 1 pulgada cuadrada por cada 4000 Btu/h del total de entrada de los aparatos."},
  {id:352, q:"Las dos aberturas de aire de combustión requeridas deben ubicarse:", opts:["Ambas a no más de 12 pulgadas del piso","Una a no más de 12 pulgadas de la parte superior y otra a no más de 12 pulgadas de la inferior","Ambas en el techo","En cualquier parte de una sola pared"], re:"Una abertura va a no más de 12 pulgadas de la parte superior del espacio y la otra a no más de 12 pulgadas de la inferior para que el aire cálido y el frío se intercambien."},
  {id:353, q:"Un conducto de gas Tipo B que sirve a un calentador atmosférico (con campana de tiro) está listado para una holgura a combustibles de:", opts:["0 pulgadas","18 pulgadas","6 pulgadas","1 pulgada"], re:"El conducto Tipo B de doble pared está listado para una holgura de 1 pulgada a material combustible, mucho menor que la que requiere el tubo conector de pared simple."},
  {id:354, q:"Un conducto de gas (Tipo B) debe terminar sobre el techo por al menos:", opts:["2 pies (y según la tabla de altura del conducto)","6 pulgadas","Sin mínimo","Siempre 10 pies"], re:"Un conducto de gas debe sobresalir al menos 2 pies sobre la superficie del techo (y cumplir los requisitos listados de altura contra distancia) para un buen tiro y dispersión."},
  {id:355, q:"La campana de tiro (draft hood) de un calentador de agua a gas atmosférico sirve para:", opts:["Aumentar la presión de gas","Filtrar el gas","Admitir aire de dilución y aliviar contracorrientes para que el quemador ventee de forma estable","Almacenar gases de combustión"], re:"La campana de tiro deja entrar aire de dilución y libera el exceso de tiro, manteniendo el venteo estable del quemador y evitando que las fluctuaciones de presión lo hagan contratirar."},
  {id:356, q:"Un calentador de agua sin tanque (a demanda) se diferencia del tipo de almacenamiento en que:", opts:["Almacena 40 galones de agua caliente","Calienta el agua solo a demanda, sin tanque de almacenamiento","No puede usar gas","No tiene caudal mínimo para activarse"], re:"Una unidad sin tanque calienta el agua instantáneamente al fluir, evitando las pérdidas en reposo de un tanque, pero necesita un caudal mínimo para encender."},
  {id:357, q:"Comparado con un calentador de almacenamiento, un calentador sin tanque reduce principalmente:", opts:["La pérdida de calor en reposo","La presión de agua","La temperatura de humos a cero","La necesidad de cualquier venteo"], re:"Como no almacena agua caliente, un calentador sin tanque elimina la pérdida en reposo de mantener un tanque caliente, mejorando la eficiencia para uso bajo a moderado."},
  {id:358, q:"La 'capacidad de la primera hora' de un calentador de almacenamiento describe:", opts:["Su periodo de garantía","El espesor de la pared del tanque","El tamaño del conducto de humos","Los galones de agua caliente que puede entregar en la primera hora desde lleno"], re:"La capacidad de la primera hora es el volumen de agua caliente que un tanque totalmente calentado puede suministrar en una hora, combinando volumen almacenado y recuperación."},
  {id:359, q:"La 'tasa de recuperación' de un calentador de agua se refiere a:", opts:["Qué tan rápido puede recalentar el agua conforme se extrae","Cuánto dura la garantía","La calibración de la válvula de alivio","La separación de las correas"], re:"La tasa de recuperación es qué tan rápido el calentador puede elevar el agua fría entrante a temperatura; una mayor entrada da una mayor recuperación."},
  {id:360, q:"Un tubo conector de venteo de pared simple de un calentador a la chimenea generalmente requiere una holgura a combustibles de:", opts:["0 pulgadas","1 pulgada","6 pulgadas","No se especifica holgura"], re:"El tubo conector de pared simple opera caliente y normalmente necesita 6 pulgadas de holgura a combustibles, por eso suele usarse Tipo B de doble pared en espacios reducidos."},
  {id:361, q:"El conducto de humos o tubo conector de venteo de un calentador debe tener pendiente:", opts:["Hacia abajo hacia el calentador","Perfectamente nivelado","Cuesta abajo hacia una trampa","Hacia arriba hacia el conducto (típicamente 1/4 pulgada por pie)"], re:"El conector debe subir hacia el conducto, comúnmente al menos 1/4 de pulgada por pie, para que los gases calientes fluyan hacia arriba y se mantenga el tiro."},
  {id:362, q:"El aire de combustión insuficiente a un calentador de agua a gas puede causar:", opts:["Combustión incompleta y monóxido de carbono peligroso","Mayor eficiencia","Solo menor temperatura de humos","Ningún efecto"], re:"Privado de aire, el quemador combustiona de forma incompleta y puede producir monóxido de carbono y hollín, por eso se requiere aire de combustión adecuado."},
  {id:363, q:"Un calentador de agua de venteo directo (combustión sellada) toma su aire de combustión de:", opts:["La habitación donde está","El exterior a través de una toma dedicada","La válvula de alivio","La charola de drenaje"], re:"Una unidad de venteo directo toma aire de combustión del exterior y ventea al exterior por un sistema sellado, así que no depende del aire de la habitación."},
  {id:364, q:"Un material rígido aprobado común para tubería de gas combustible en un edificio es:", opts:["PVC","ABS","Tubo de acero negro","Cobre Tipo M para DWV"], re:"El tubo de acero negro, comúnmente cédula 40, es un material estándar para gas combustible; también se usan CSST y, donde se permite, cierto cobre."},
  {id:365, q:"CSST significa:", opts:["Tubo de suministro de acero fundido","Tubo de cobre blando recubierto","Tubería corrugada de acero inoxidable","Trampa central de corte de seguridad"], re:"CSST es tubería corrugada de acero inoxidable, un producto flexible listado para gas que se instala según las instrucciones del fabricante."},
  {id:366, q:"Un sistema de tubería de gas CSST debe estar eléctricamente puenteado (bonded) con un conductor no menor que:", opts:["No. 6 AWG de cobre","No. 14 AWG de cobre","No. 18 AWG de cobre","No se necesita puenteo"], re:"El CSST debe puentearse al sistema de puesta a tierra eléctrica con al menos un conductor de cobre No. 6 AWG para disipar la energía de rayos cercanos y reducir el arqueo."},
  {id:367, q:"La razón principal por la que el CSST debe puentearse es:", opts:["Reducir el riesgo de arqueo y perforación por energía de rayos","Aumentar la presión de gas","Bajar la temperatura de humos","Acelerar el flujo de gas"], re:"El puenteo baja el voltaje que puede acumularse en el CSST de pared delgada durante un rayo, reduciendo la posibilidad de un arco que perfore e incendie el gas."},
  {id:368, q:"Una trampa de sedimento (drip leg) en un aparato de gas se instala para:", opts:["Reducir la presión de gas","Ventear la línea de gas","Aumentar el flujo","Atrapar suciedad y humedad antes de que lleguen al control del aparato"], re:"La trampa de sedimento recoge residuos y condensado para que se depositen en vez de ensuciar la válvula de gas o el orificio del quemador del aparato."},
  {id:369, q:"Una trampa de sedimento se forma más comúnmente de:", opts:["Una válvula de retención","Una unión solamente","Un regulador de presión","Una te con un niple tapado en la salida inferior"], re:"La trampa suele ser una conexión en te con un niple vertical tapado abajo, para que los residuos caigan al ramal sin salida antes de que el gas gire hacia el aparato."},
  {id:370, q:"¿En la entrada de cuáles aparatos se requiere una trampa de sedimento?", opts:["Solo el medidor de gas","Calentadores de agua, calefactores (furnaces) y calderas (según el código)","Solo asadores exteriores","En ninguno"], re:"Se requiere una trampa de sedimento aguas abajo de la llave de paso en aparatos como calentadores de agua, calefactores y calderas; ciertos aparatos como estufas pueden estar exentos."},
  {id:371, q:"Cada aparato de gas debe tener una llave de paso que sea:", opts:["Solo en el medidor","Fácilmente accesible y en la misma habitación, cerca del aparato","Detrás del muro","Sellada cerrada"], re:"Una llave de paso del aparato debe estar en la misma habitación y fácilmente accesible cerca del aparato para poder cortar el gas para servicio o emergencias."},
  {id:372, q:"Un conector flexible de aparato de gas puede tener una longitud total que no exceda:", opts:["3 pies","Sin límite","12 pies","6 pies"], re:"Un conector de aparato listado se limita a 6 pies en total, y solo puede usarse un conector por aparato."},
  {id:373, q:"Un conector flexible de aparato de gas NO debe:", opts:["Estar listado","Pasar por un muro, piso o tabique, ni quedar oculto","Conectarse a una llave de paso","Ser de una sola pieza"], re:"Un conector no puede correr a través de muros, pisos, tabiques o techos, ni quedar oculto; la tubería del edificio debe llegar a la misma habitación del aparato."},
  {id:374, q:"Unir dos conectores flexibles de gas para ganar longitud está:", opts:["Permitido","No permitido","Requerido para estufas","Permitido solo en exteriores"], re:"Solo se permite un conector por aparato; empalmar dos juntos está prohibido por la norma del producto y por el código."},
  {id:375, q:"La llave de paso del aparato para un conector flexible se instala:", opts:["Dentro del aparato","Solo en el medidor","En el techo","Donde el conector se une a la tubería rígida del edificio"], re:"La llave de paso se coloca en el punto donde el conector se une a la tubería fija del edificio, para que quede al alcance en la misma habitación del aparato."},
  {id:376, q:"Por lo general NO se permite que el CSST quede:", opts:["Instalado en interiores","Usado en absoluto","Expuesto a daño físico sin protección","Conectado a tubo negro"], re:"Donde el CSST pudiera ser golpeado o rozado debe protegerse (por ejemplo con placas de impacto o fundas), ya que su pared delgada se daña con facilidad."},
  {id:377, q:"El tubo de gas de acero negro se une mediante:", opts:["Juntas roscadas (o soldadura) con compuesto sellador de roscas aprobado","Cemento solvente","Anillos de engargolado","Un anillo de cera"], re:"El tubo de gas de acero se rosca (o se suelda) y se sella con un compuesto para roscas listado para gas combustible; los cementos solventes son para plásticos, no para gas."},
  {id:378, q:"El tubo de acero galvanizado generalmente se evita para gas natural porque:", opts:["Es demasiado resistente","El zinc que se desprende puede tapar controles y orificios","No puede roscarse","No se vende en EE. UU."], re:"El galvanizado de zinc puede desprenderse dentro del tubo y alojarse en válvulas y orificios, por eso se prefiere el acero negro para gas combustible."},
  {id:379, q:"La tubería de gas metálica subterránea se protege contra la corrosión mediante:", opts:["Dejarla desnuda","Pintarla solo de blanco","Llenarla de aceite","Recubrimiento, envoltura o protección anticorrosiva aprobada"], re:"El tubo de gas metálico enterrado debe protegerse de la corrosión con un recubrimiento, envoltura o medio catódico aprobado para que no se oxide hasta perforarse."},
  {id:380, q:"Un conector de aparato está certificado conforme a la norma:", opts:["ASTM D1785","ANSI Z21.24 / CSA 6.10","NEC Artículo 250","Solo ASME B16.3"], re:"Los conectores de aparato de gas listados están certificados conforme a ANSI Z21.24/CSA 6.10, que los limita a 6 pies y al uso en un solo aparato."},
  {id:381, q:"La tubería de gas debe dimensionarse para suministrar:", opts:["Solo el aparato más pequeño","La mitad de la carga total","La demanda máxima combinada de todos los aparatos conectados","El doble de la capacidad del medidor"], re:"El sistema se dimensiona para la suma de las entradas máximas de los aparatos para que todos puedan operar a la vez sin quedarse sin gas."},
  {id:382, q:"Para dimensionar un ramal de tubo de gas debes conocer su longitud y la carga conectada expresada en:", opts:["Galones por minuto","Btu por hora (o pies cúbicos por hora)","Voltios","Libras de fuerza"], re:"El tubo de gas se dimensiona a partir de la demanda en Btu/h (o pcfh) y la longitud desarrollada, leídas en la tabla de dimensionamiento correcta para el gas y la presión."},
  {id:383, q:"Para una longitud y carga dadas, aumentar la caída de presión permitida en una línea de gas permite usar:", opts:["Un tubo más grande","Un tubo más pequeño","Ningún tubo","Solo un tubo de cobre"], re:"Permitir más caída de presión a lo largo de un tramo significa que un tubo más pequeño aún puede entregar el flujo requerido, lo cual se refleja en las tablas de dimensionamiento."},
  {id:384, q:"Conforme aumenta la longitud desarrollada de un tramo de tubo de gas, para la misma carga el tamaño de tubo requerido:", opts:["Disminuye","Se mantiene igual","Aumenta","Se vuelve cero"], re:"Los tramos más largos pierden más presión por fricción, así que se necesita un tubo más grande para llevar la misma carga de Btu la distancia requerida."},
  {id:385, q:"Los aparatos estándar de gas natural a baja presión en una vivienda operan a una presión de entrega de cerca de:", opts:["7 pulgadas de columna de agua","5 psi","60 psi","30 psi"], re:"El gas natural residencial típico se entrega a aproximadamente 7 pulgadas de columna de agua (cerca de 1/4 psi); las tablas de dimensionamiento se basan en esa baja presión."},
  {id:386, q:"Un sistema de tubería de gas nuevo debe:", opts:["Llenarse de agua antes de usarse","Enterrarse antes de probarse","Probarse a presión por fugas antes de ponerse en servicio","Dejarse abierto al aire"], re:"La tubería de gas se prueba a presión y se demuestra libre de fugas antes de admitir gas y poner el sistema en servicio."},
  {id:387, q:"Conforme al código Uniforme/California, una prueba de presión de gas generalmente se mantiene a no menos de:", opts:["10 psi durante al menos 15 minutos","1 psi durante 1 minuto","100 psi durante 1 hora","No se requiere presión"], re:"La prueba de campo estándar es de al menos 10 psi mantenidos al menos 15 minutos (más según la autoridad) sin caída perceptible de presión."},
  {id:388, q:"La presión de prueba para tubería de gas debe ser al menos cuántas veces la presión de trabajo (con un piso establecido)?", opts:["La mitad","Diez veces","Solo igual a la presión de trabajo","Una y media veces"], re:"La presión de prueba debe ser no menor que 1-1/2 veces la presión de trabajo propuesta, y en ningún caso menor que el mínimo del código, para probar las juntas."},
  {id:389, q:"Durante una prueba de presión de gas, los aparatos con capacidad menor a la presión de prueba deben:", opts:["Dejarse conectados y abiertos","Aislarse de la tubería (cerrados con su llave o desconectados)","Operarse a fuego máximo","Retirarse del edificio"], re:"Los aparatos no diseñados para la presión de prueba se aíslan cerrando sus llaves o desconectándolos, para que la prueba no los dañe."},
  {id:390, q:"Una prueba de presión de gas se lee con:", opts:["Un termómetro","Un manómetro o medidor apropiado para la presión","Un voltímetro","Solo un medidor de flujo"], re:"La presión de prueba mantenida se observa en un manómetro o medidor adecuado al rango, y cualquier caída perceptible señala una fuga a localizar y corregir."},
  {id:391, q:"La trampa de sedimento normalmente se ubica:", opts:["Solo en el medidor","Aguas abajo de la llave del aparato, cerca de la entrada del aparato","En el techo","Dentro del conducto de humos del aparato"], re:"Se coloca después de la llave de paso y lo más cerca posible de la entrada del aparato, para captar residuos justo antes de que el gas entre al control."},
  {id:392, q:"Una fuga de gas se verifica en las juntas con:", opts:["Una llama abierta","Solución detectora de fugas aprobada (burbujas) o un detector listado","Las manos desnudas","Un trapo húmedo"], re:"Las fugas se localizan con una solución de burbujas no corrosiva o un detector de gas listado, nunca con una llama abierta, que sería peligrosa."},
  {id:393, q:"Una válvula de corte de gas por sismo (sísmica) está diseñada para:", opts:["Aumentar la presión de gas","Detener automáticamente el flujo de gas durante un fuerte movimiento","Reemplazar el medidor","Calentar el gas"], re:"Una válvula de corte sísmica cierra el gas durante un fuerte movimiento del terreno, reduciendo el riesgo de incendios alimentados por gas tras un sismo."},
  {id:394, q:"Cuando dos aparatos comparten una línea de gas, la sección que alimenta a ambos debe dimensionarse para:", opts:["Solo el aparato más grande","Solo el aparato más pequeño","La suma de la demanda de ambos aparatos","La mitad de cada uno"], re:"Una sección común debe llevar la carga combinada de cada aparato que sirve; solo el ramal final hacia un solo aparato lleva esa carga única."},
  {id:395, q:"Un sistema de tubería de gas que falla su prueba de presión al perder presión indica:", opts:["Que el tubo es del tamaño correcto","Una fuga que debe localizarse y repararse antes del servicio","Que el gas está demasiado frío","Que el medidor es demasiado grande"], re:"Una caída durante la prueba significa una fuga; debe localizarse y corregirse, y luego volver a probar el sistema, antes de abrir el gas."},
  {id:396, q:"El propósito de una llave de paso accesible cerca de un calefactor o calentador de agua es:", opts:["Aumentar la presión","Permitir cortar el gas a ese aparato para servicio o emergencia","Ventear el conducto de humos","Dimensionar el tubo"], re:"La llave de paso local permite a un técnico u ocupante aislar rápido solo ese aparato sin cortar el gas de todo el edificio."},
  {id:397, q:"Antes de volver a poner en servicio una línea de gas reparada, el plomero debe:", opts:["Omitir cualquier prueba","Volver a probar a presión y confirmar que aguanta, luego purgar el aire correctamente","Encender todos los quemadores a la vez","Dejarla abierta toda la noche"], re:"Tras una reparación, la línea se vuelve a probar por estanqueidad y luego se purga de aire para que solo gas llegue a los quemadores al reencender."},
  {id:398, q:"Las tablas de dimensionamiento de tubería de gas se ingresan usando el tipo de gas, la caída de presión permitida y la del tramo:", opts:["Color","Longitud desarrollada más larga","Nombre del instalador","Temperatura exterior"], re:"El dimensionamiento se basa en la longitud más larga del tramo (y la carga conectada en Btu), así que la trayectoria más exigente gobierna el tamaño de tubo elegido."},
  {id:399, q:"Una pierna de goteo (drip leg) se diferencia de una trampa de sedimento en que la pierna de goteo recoge principalmente:", opts:["Corriente eléctrica","Líquido (condensado) que de otro modo llegaría al aparato","Exceso de presión","Aire de combustión"], re:"Una pierna de goteo da a los líquidos un punto bajo donde acumularse; en la práctica la misma te con niple tapado también sirve de trampa de sedimento captando suciedad y humedad."},
  {id:400, q:"Una línea de gas subdimensionada que sirve a un calefactor y un calentador de agua operando juntos probablemente causará:", opts:["Mayor eficiencia","Una caída de presión que priva a los quemadores y causa mala combustión","Solo menor temperatura de humos","Ningún efecto"], re:"Si el tubo compartido es muy pequeño, la demanda simultánea baja la presión y priva a los quemadores, causando llamas débiles y combustión incompleta."},
  {id:401, q:"¿Cuál es la mejor definición de conexión cruzada?", opts:["La unión de dos tuberías principales de agua potable de distinto diámetro","Un accesorio en T instalado en un circuito de recirculación de agua caliente","El punto donde el drenaje del edificio se convierte en la alcantarilla del edificio","Cualquier conexión real o potencial entre un sistema de agua potable y una fuente no potable"], re:"Una conexión cruzada es cualquier enlace real o potencial por el cual podrían entrar contaminantes al suministro potable. Controlarla es el objetivo central de la prevención de reflujo."},
  {id:402, q:"El reflujo es la inversión indeseada del flujo en un sistema de tuberías causada por:", opts:["Velocidad excesiva del agua en la tubería principal","Contrapresión o sifonaje inverso","Demanda normal en los artefactos aguas abajo","Expansión térmica del calentador de agua"], re:"El reflujo ocurre por contrapresión (la presión aguas abajo supera la de suministro) o sifonaje inverso (presión de suministro negativa). Ambos pueden arrastrar contaminantes al sistema potable."},
  {id:403, q:"El sifonaje inverso (backsiphonage) se produce por:", opts:["Una bomba aguas abajo que empuja el agua hacia la tubería principal","Una presión negativa o reducida en la tubería de suministro potable","Una caldera que opera por encima de la presión de la calle","Cerrar una válvula demasiado rápido (golpe de ariete)"], re:"El sifonaje inverso resulta de una presión negativa (subatmosférica) en el suministro, como una rotura de la tubería principal o una demanda intensa, que succiona agua no potable hacia atrás."},
  {id:404, q:"El reflujo por contrapresión ocurre cuando:", opts:["La presión de suministro cae por debajo de la presión atmosférica","Se deja un grifo abierto durante un corte de la tubería principal","La presión del sistema aguas abajo supera la presión del suministro potable","Se provee un espacio de aire en el artefacto"], re:"El reflujo por contrapresión sucede cuando una fuente aguas abajo (una bomba, caldera o tanque elevado) eleva la presión por encima del suministro y fuerza el flujo hacia atrás."},
  {id:405, q:"En el control de conexiones cruzadas, una conexión de 'alto riesgo' (contaminante) es la que podría:", opts:["Afectar solo el sabor, olor o color del agua","Provocar enfermedad, propagar enfermedades o ser letal si se consume","Reducir el flujo en el artefacto más alejado","Aumentar la factura de agua del cliente"], re:"Una conexión cruzada de alto riesgo (contaminante) involucra sustancias que podrían causar enfermedad o muerte. Requiere la mayor protección, como un espacio de aire o un conjunto RP."},
  {id:406, q:"Una conexión cruzada de 'bajo riesgo' (contaminante estético) es la que:", opts:["Podría ser letal para un consumidor","Siempre requiere un conjunto de principio de presión reducida","No puede protegerse legalmente con un conjunto de doble retención","Deterioraría la calidad del agua (sabor, olor, color) pero no pondría en peligro la salud"], re:"Una conexión de bajo riesgo afecta la calidad estética del agua sin representar un riesgo para la salud. Un conjunto de doble retención suele ser una protección aceptable."},
  {id:407, q:"¿Qué dispositivo brinda la protección más alta y positiva contra el reflujo?", opts:["Un rompedor de vacío atmosférico","Un conjunto de doble válvula de retención","Un espacio de aire correctamente instalado","Un rompedor de vacío para grifo de manguera"], re:"Un espacio de aire físico bien dimensionado es la protección de reflujo más confiable porque no tiene piezas mecánicas que puedan fallar. Sirve para los riesgos más altos."},
  {id:408, q:"El grado de protección contra reflujo requerido para una conexión dada se elige principalmente según:", opts:["El material de tubería usado aguas abajo","El grado de riesgo y el tipo de reflujo posible","La antigüedad del edificio","Si el artefacto es solo residencial o comercial"], re:"La protección se adecua al grado de riesgo (bajo o alto) y a si es posible contrapresión, sifonaje inverso o ambos. Esto determina qué conjunto es aceptable."},
  {id:409, q:"Una conexión cruzada directa es aquella en la que la fuente no potable puede ser forzada al sistema potable por:", opts:["Solo sifonaje inverso","Un espacio de aire","Evaporación","Contrapresión (una conexión física continua bajo presión)"], re:"Una conexión cruzada directa está sujeta a contrapresión porque la fuente contaminante está físicamente conectada al sistema potable y puede empujarse hacia atrás bajo presión."},
  {id:410, q:"Una conexión cruzada indirecta (como una entrada sumergida abierta a la atmósfera) suele estar sujeta a:", opts:["Sifonaje inverso","Solo contrapresión","Solo expansión térmica","Ni contrapresión ni sifonaje inverso"], re:"Una conexión cruzada indirecta (como una entrada sumergida abierta a la atmósfera) queda expuesta al sifonaje inverso cuando la presión de suministro se vuelve negativa."},
  {id:411, q:"Un ejemplo clásico de peligro de conexión cruzada es:", opts:["Un caño de grifo que termina muy por encima del borde de rebose","Una manguera sumergida en un balde de químicos mientras está conectada a un grifo exterior","Una terminal de ventilación a través del techo","Un tapón de limpieza en la base de una columna"], re:"Una manguera de jardín sumergida en un contaminante y conectada a un grifo de manguera es una conexión cruzada de manual que puede sifonar contaminantes al suministro potable."},
  {id:412, q:"Los programas de control de conexiones cruzadas buscan proteger principalmente:", opts:["El sistema de drenaje y ventilación","Los artefactos contra el golpe de ariete","El suministro público de agua potable contra la contaminación","El calentador de agua contra las incrustaciones"], re:"El control de conexiones cruzadas existe para mantener los contaminantes fuera del sistema público de agua potable, protegiendo a los consumidores de riesgos transmitidos por el agua."},
  {id:413, q:"La contención (containment), en la terminología de conexiones cruzadas, se refiere a la protección contra reflujo instalada:", opts:["En cada artefacto individual dentro del edificio","Solo en el montante de rociadores contra incendios","En la conexión de servicio (medidor) para aislar todo el predio","Dentro del calentador de agua"], re:"La contención protege la tubería pública colocando un conjunto en la conexión de servicio, de modo que todo el predio quede aislado del suministro de la empresa."},
  {id:414, q:"El aislamiento (protección en el artefacto), a diferencia de la contención, significa proteger contra el reflujo:", opts:["Solo en la conexión de servicio del predio","En el punto específico de cada peligro dentro del predio","En el lado de la empresa de agua respecto del medidor","Solo en el artefacto más alto del edificio"], re:"El aislamiento coloca la protección en cada conexión cruzada interna para que un peligro no pueda llegar a otras partes del propio sistema potable del edificio."},
  {id:415, q:"¿Qué conexión se clasificaría generalmente como de ALTO riesgo?", opts:["Un lavavajillas residencial con un espacio de aire integrado","Un bebedero","Un sistema de riego de césped con inyección de químicos","Una salida de bañera por encima del borde"], re:"Un sistema de riego que puede inyectar fertilizantes o pesticidas es un peligro alto (de salud) y requiere protección de alto nivel, como un conjunto RP."},
  {id:416, q:"Existe una entrada sumergida siempre que una salida de suministro de agua:", opts:["Termina por encima del borde de rebose del receptor","Puede inundarse de modo que la salida quede por debajo del nivel del líquido al que descarga","Está equipada con un espacio de aire","Descarga a un receptor de desagüe indirecto"], re:"Una entrada sumergida es cualquier salida de suministro que pueda quedar cubierta por el líquido al que sirve, creando una conexión cruzada de sifonaje inverso que debe protegerse."},
  {id:417, q:"Una caldera o circuito de calefacción hidrónica conectada al suministro potable es principalmente una preocupación de reflujo por:", opts:["Sifonaje inverso por baja presión de la calle","Contrapresión más el peligro químico/térmico del agua de la caldera","Solo cambios estéticos de sabor","Velocidad de flujo excesiva"], re:"Una caldera opera por encima de la presión de suministro (contrapresión) y puede contener químicos de tratamiento, por lo que su conexión de reposición es una preocupación de alto riesgo por contrapresión."},
  {id:418, q:"Un suministro de agua auxiliar o secundario (como un pozo privado) conectado a un predio servido por agua municipal es relevante porque:", opts:["Crea una posible conexión cruzada que puede contaminar la tubería pública","Siempre mejora la calidad del agua potable","Elimina la necesidad de cualquier dispositivo de reflujo","Está exento de las reglas de conexión cruzada"], re:"Un suministro auxiliar no aprobado puede refluir al sistema público, por lo que estos predios suelen requerir protección de contención en el servicio."},
  {id:419, q:"El espacio de aire vertical mínimo entre una salida de agua potable y el borde de rebose de un artefacto es generalmente:", opts:["1 pulgada (25 mm)","1/2 pulgada (13 mm)","2 pulgadas (51 mm)","3 pulgadas (76 mm)"], re:"El Código de Plomería fija un espacio de aire mínimo de 1 pulgada. Las salidas más pequeñas igual requieren este mínimo absoluto aunque el espacio calculado sea menor."},
  {id:420, q:"Por regla general, el espacio de aire mínimo debe ser al menos cuántas veces la abertura efectiva (diámetro) de la salida de suministro?", opts:["Una vez","Dos veces","Seis veces","Cuatro veces"], re:"El espacio de aire debe ser al menos el doble del diámetro de la abertura efectiva (pero nunca menos de 1 pulgada) cuando la salida no está cerca de una pared."},
  {id:421, q:"Cuando una salida de suministro está cerca de una pared, el espacio de aire requerido aumenta a al menos cuántas veces la abertura efectiva?", opts:["Tres veces","Dos veces","Cuatro veces","Una vez y media"], re:"Cerca de una pared, el efecto de salpicadura/obstrucción aumenta el requisito a tres veces la abertura efectiva. Varias paredes cercanas requieren aún más."},
  {id:422, q:"La 'abertura efectiva' usada para dimensionar un espacio de aire es:", opts:["El diámetro exterior de la tubería de suministro","El área transversal mínima de la abertura de suministro de agua (su menor diámetro)","La longitud del borde de rebose","La profundidad del receptor"], re:"La abertura efectiva es la sección transversal más pequeña de la salida de descarga. El espacio de aire se mide desde esa abertura hacia abajo hasta el borde de rebose."},
  {id:423, q:"Un conjunto de reflujo de principio de presión reducida (RP) consta de:", opts:["Una sola válvula de retención y un grifo de prueba","Una entrada de aire que abre solo a presión atmosférica","Un rompedor de vacío y una sola llave de paso","Dos válvulas de retención independientes con una válvula de alivio diferencial entre ellas"], re:"Un conjunto RP tiene dos válvulas de retención independientes y una válvula de alivio diferencial en la zona entre ellas, más llaves de paso y cuatro grifos de prueba."},
  {id:424, q:"El conjunto de principio de presión reducida es aceptable para proteger contra:", opts:["Solo sifonaje inverso, bajo riesgo","Solo contrapresión, bajo riesgo","Ni contrapresión ni sifonaje inverso","Tanto contrapresión como sifonaje inverso, incluido alto riesgo"], re:"El conjunto RP protege tanto contra contrapresión como contra sifonaje inverso y está aprobado para servicio de alto riesgo, siendo el conjunto comprobable más versátil."},
  {id:425, q:"La válvula de alivio de un conjunto RP descarga a la atmósfera cada vez que:", opts:["La presión de suministro supera los 80 psi","Ambas retenciones están reteniendo herméticamente","La demanda aguas abajo es alta","La zona entre las retenciones pierde su diferencial de presión requerido"], re:"Si alguna retención tiene fuga y el diferencial a través de la válvula de alivio cae demasiado, el alivio abre y descarga la zona a la atmósfera: su acción a prueba de fallos."},
  {id:426, q:"Un conjunto RP se describe como 'a prueba de fallos hacia la atmósfera' porque:", opts:["Una falla de retención hace que la válvula de alivio descargue, señalando y evitando el reflujo","Sella más fuerte a medida que falla","Deja pasar agua silenciosamente si falla","No requiere pruebas"], re:"Una retención fallida abre la válvula de alivio, descargando agua al exterior en lugar de dejar pasar agua contaminada: a la vez una salvaguarda y una advertencia visible."},
  {id:427, q:"Un conjunto de doble válvula de retención (DCVA) está compuesto por:", opts:["Una válvula de retención más una ventilación atmosférica","Una válvula de alivio entre dos retenciones","Dos válvulas de retención independientes con resorte en serie, con llaves de paso y grifos de prueba","Una sola retención con un rompedor de vacío"], re:"Un DCVA usa dos retenciones independientes con resorte en serie, dos llaves de paso y grifos de prueba, pero sin válvula de alivio a la atmósfera."},
  {id:428, q:"Un conjunto de doble válvula de retención está aprobado generalmente para:", opts:["Conexiones de alto riesgo (de salud)","Solo sifonaje inverso","Conexiones de bajo riesgo sujetas a contrapresión o sifonaje inverso","Ninguna condición de reflujo"], re:"El DCVA sirve para situaciones de bajo riesgo con contrapresión o sifonaje inverso. No está aprobado para conexiones de alto riesgo (contaminantes)."},
  {id:429, q:"La diferencia física clave entre un DCVA y un conjunto RP es que el RP además tiene:", opts:["Una segunda llave de paso","Grifos de prueba","Una entrada más grande","Una válvula de alivio diferencial en la zona central"], re:"Ambos tienen dos retenciones y llaves de paso; solo el RP añade la válvula de alivio diferencial, que es lo que lo califica para protección de alto riesgo."},
  {id:430, q:"Un rompedor de vacío atmosférico (AVB) protege contra:", opts:["Solo contrapresión","Tanto contrapresión como sifonaje inverso","Expansión térmica","Solo sifonaje inverso"], re:"Un AVB protege únicamente contra el sifonaje inverso. Nunca debe instalarse donde pueda quedar sometido a contrapresión."},
  {id:431, q:"Un rompedor de vacío atmosférico debe instalarse de modo que su nivel crítico quede al menos:", opts:["En o por debajo del borde de rebose","6 pulgadas por encima de la tubería aguas abajo más alta y del borde de rebose","1 pulgada por encima de la tubería aguas abajo más alta y del borde de rebose","12 pulgadas por encima del borde de rebose"], re:"Un AVB debe quedar al menos 6 pulgadas por encima de la salida aguas abajo más alta y del borde de rebose para que la entrada de aire pueda romper un sifón correctamente."},
  {id:432, q:"Una llave de paso, válvula de retención u otro control aguas abajo de un rompedor de vacío atmosférico está:", opts:["Requerido para el funcionamiento correcto","Prohibido, porque puede mantener presión sobre el AVB","Recomendado por conveniencia","Permitido si es una válvula de bola"], re:"No puede colocarse ninguna válvula aguas abajo de un AVB; cualquier control aguas abajo podría someterlo a presión continua o contrapresión, que no puede soportar."},
  {id:433, q:"Un rompedor de vacío atmosférico no está diseñado para estar bajo presión continua de agua por más de aproximadamente:", opts:["1 hora","24 horas continuas sin límite","12 horas","Cualquier período está bien"], re:"Un AVB está diseñado para uso intermitente y no debe estar bajo presión continua más allá de unas 12 horas, o su disco puede pegarse y fallar."},
  {id:434, q:"Un rompedor de vacío a presión (PVB) se diferencia de un AVB en que el PVB:", opts:["Puede mantenerse bajo presión continua y protege contra el sifonaje inverso","No puede ser comprobado","Protege contra la contrapresión","Debe instalarse por debajo del borde de rebose"], re:"Un PVB tiene una entrada de aire con resorte y una retención interna, por lo que puede permanecer bajo presión continua. Como el AVB, protege solo contra el sifonaje inverso, no la contrapresión."},
  {id:435, q:"Un conjunto rompedor de vacío a presión debe tener su nivel crítico instalado al menos:", opts:["6 pulgadas por encima de la tubería aguas abajo más alta y del borde de rebose","12 pulgadas por encima de la tubería aguas abajo más alta y del borde de rebose","1 pulgada por encima del borde de rebose","Al nivel de la salida más alta"], re:"El nivel crítico de un PVB debe estar al menos 12 pulgadas por encima de la salida aguas abajo más alta y del borde de rebose, más alto que el requisito del AVB."},
  {id:436, q:"Las salidas con rosca para manguera (grifos exteriores) que suministran agua potable deben protegerse con:", opts:["Solo un conjunto de presión reducida","Un conjunto detector de doble retención","Un rompedor de vacío para grifo de manguera no removible (o equivalente)","Ninguna protección si están en el exterior"], re:"Las salidas de manguera requieren un rompedor de vacío para grifo de manguera no removible para evitar el sifonaje inverso a través de una manguera conectada, una conexión cruzada muy común."},
  {id:437, q:"Un rompedor de vacío para grifo de manguera debe ser 'no removible' para que:", opts:["Pueda reutilizarse en otros grifos","Aumente el caudal de la manguera","No pueda quitarse fácilmente, anulando la protección de reflujo","Pueda probarse anualmente"], re:"Hacer el rompedor no removible (rompiendo el tornillo de fijación) mantiene la protección permanentemente en su lugar para que un usuario no pueda quitarla y crear un peligro."},
  {id:438, q:"¿Qué protección contra reflujo NO se comprueba en campo con un manómetro y funciona solo por separación física?", opts:["El espacio de aire","El conjunto de principio de presión reducida","El conjunto de doble válvula de retención","El conjunto rompedor de vacío a presión"], re:"Un espacio de aire no tiene piezas móviles y se verifica por medición, no con un manómetro de prueba. El RP, el DCVA y el PVB son conjuntos mecánicos que se comprueban en campo."},
  {id:439, q:"¿Cuántos grifos de prueba tiene típicamente un conjunto RP o de doble retención para la comprobación en campo?", opts:["Uno","Dos","Seis","Cuatro"], re:"Estos conjuntos vienen con cuatro grifos de prueba, lo que permite al comprobador leer las presiones a través de cada retención y de la válvula de alivio (en un RP)."},
  {id:440, q:"Durante la comprobación de un conjunto RP, la válvula de alivio diferencial debe abrir antes de que el diferencial de la zona caiga por debajo de aproximadamente:", opts:["2 psi","1 psi","10 psi","20 psi"], re:"Las normas exigen que la válvula de alivio abra a no menos de unos 2 psi de diferencial, asegurando que descargue antes de que la zona central pierda su presión protectora."},
  {id:441, q:"En un conjunto RP, la zona central entre las dos retenciones se mantiene a una presión que es:", opts:["Mayor que la presión de suministro","Igual a la presión aguas abajo","Siempre atmosférica","Menor que la presión de suministro pero por encima de la atmosférica"], re:"La zona se mantiene a una presión reducida —por debajo del suministro pero por encima de la atmosférica— para que cualquier fuga que pase la primera retención sea detectada y aliviada."},
  {id:442, q:"Los conjuntos mecánicos de prevención de reflujo (RP, DCVA, PVB) en general deben comprobarse para verificar su funcionamiento correcto:", opts:["Solo al momento de la instalación","Cada diez años","Al instalarse y al menos anualmente (periódicamente) después","Nunca, una vez instalados"], re:"Los conjuntos comprobables deben probarse al instalarse y al menos anualmente por un comprobador certificado, porque los sellos y resortes internos pueden degradarse con el tiempo."},
  {id:443, q:"Un conjunto de reflujo debe instalarse donde sea:", opts:["Enterrado directamente en el suelo para protegerlo","Oculto dentro de una pared terminada","Sumergido para evitar el congelamiento","Accesible para comprobación, mantenimiento y descarga de la válvula de alivio"], re:"Los conjuntos deben ser accesibles para poder comprobarse y repararse, y un RP debe drenar libremente; no puede instalarse donde pueda inundarse."},
  {id:444, q:"Un conjunto de principio de presión reducida NO puede instalarse:", opts:["En una fosa o cámara bajo nivel sujeta a inundación","Sobre el nivel del suelo en una sala con calefacción","En un tramo horizontal con espacio libre debajo del puerto de alivio","Donde sea accesible para la comprobación"], re:"Como su válvula de alivio descarga a la atmósfera, un RP no puede colocarse en una fosa que pueda inundarse y sumergir la abertura de alivio, anulando su protección."},
  {id:445, q:"El puerto de entrada de aire (ventilación) de un rompedor de vacío atmosférico o a presión funciona:", opts:["Abriendo para admitir aire y romper el vacío cuando cae la presión de suministro","Sellando el suministro cuando la presión es alta","Descargando agua continuamente","Reduciendo la presión aguas abajo"], re:"Cuando la presión de suministro cae, la entrada de aire abre y deja entrar aire atmosférico, rompiendo el sifón para que el agua contaminada no pueda ser succionada hacia atrás."},
  {id:446, q:"El método de bucle barométrico para proteger contra el sifonaje inverso se basa en un bucle de tubería que se eleva al menos aproximadamente:", opts:["10 pies","20 pies","50 pies","35 pies"], re:"Un bucle barométrico debe elevarse unos 35 pies para que la presión atmosférica no pueda subir el agua por encima del bucle, evitando el sifonaje inverso. No detiene la contrapresión."},
  {id:447, q:"¿Qué conjunto se usa comúnmente en un sistema de rociadores contra incendios de bajo riesgo que puede ver contrapresión?", opts:["Rompedor de vacío atmosférico","Rompedor de vacío para grifo de manguera","Conjunto detector de doble retención","Espacio de aire"], re:"Un conjunto detector de doble retención es común en sistemas contra incendios de bajo riesgo; detiene contrapresión y sifonaje inverso e incluye un derivación medida para detectar fugas."},
  {id:448, q:"Un rompedor de vacío resistente a derrames (SVB) es esencialmente un rompedor de vacío a presión que:", opts:["Protege contra la contrapresión","Puede instalarse por debajo del borde de rebose","Minimiza el derrame de agua durante el funcionamiento normal","No requiere altura mínima de montaje"], re:"Un SVB es una variante del PVB diseñada para limitar el derrame de agua al estar presurizado. Aún protege solo contra el sifonaje inverso y necesita el mismo nivel crítico elevado."},
  {id:449, q:"Un rompedor de vacío atmosférico debe instalarse:", opts:["Aguas arriba de todas las válvulas","En el lado de descarga (aguas abajo) de la última válvula, por encima del borde de rebose","Por debajo del artefacto al que sirve","En una caja de válvulas enterrada"], re:"El AVB va en el lado de descarga de la última válvula y por encima del borde de rebose, para que ninguna válvula pueda mantener presión sobre él y la ruptura del sifón sea efectiva."},
  {id:450, q:"El desagüe indirecto de un lavavajillas comercial o fregadero de preparación de alimentos debe descargar al receptor a través de:", opts:["Una tubería rígida directa a la alcantarilla","Un conjunto de doble válvula de retención en el desagüe","Un espacio de aire","Un rompedor de vacío para grifo de manguera en el desagüe"], re:"El desagüe indirecto de equipos relacionados con alimentos debe descargar a través de un espacio de aire en el receptor para que las aguas residuales no puedan volver al equipo."},
  {id:451, q:"Al comprobar un conjunto de doble válvula de retención, cada válvula de retención debe mantener un diferencial estático mínimo de al menos:", opts:["0,5 psi","5 psi","10 psi","1 psi"], re:"Cada retención de un DCVA debe mantener al menos 1 psi en el sentido del flujo contra la presión inversa para aprobar, demostrando que asienta herméticamente."},
  {id:452, q:"Solo debe instalarse un conjunto de reflujo aprobado/listado para el uso, lo que significa que ha sido:", opts:["Pintado del color correcto","Probado y listado por una norma/laboratorio reconocido y aceptado por la autoridad","Fabricado nacionalmente","Instalado por el propietario"], re:"Los conjuntos deben ser de un tipo y modelo aprobado (listado) aceptado por la autoridad competente, asegurando que cumplen normas de desempeño reconocidas."},
  {id:453, q:"La principal limitación que comparten tanto el rompedor de vacío atmosférico como el de presión es que:", opts:["No pueden instalarse al aire libre","Deben comprobarse a diario","No pueden usarse en sistemas de riego","No protegen contra la contrapresión"], re:"Ninguno de los rompedores de vacío protege contra la contrapresión; solo rompen el sifonaje inverso. Donde sea posible la contrapresión, se requiere un conjunto de tipo retención."},
  {id:454, q:"Se necesita control de expansión térmica en un sistema cerrado porque un dispositivo de reflujo o una retención:", opts:["Baja la temperatura del calentador de agua","Elimina cualquier posibilidad de reflujo aguas abajo","Aumenta los caudales de los artefactos","Impide que el agua calentada se expanda de regreso a la tubería principal, elevando la presión"], re:"Cuando una retención o conjunto de reflujo cierra el suministro, el agua calentada no puede expandirse hacia la tubería principal, por lo que se necesita un tanque de expansión para controlar la presión creciente."},
  {id:455, q:"Un conjunto detector de doble retención se diferencia de un DCVA estándar por agregar:", opts:["Una segunda válvula de alivio","Una ventilación atmosférica","Un pequeño bucle de derivación medido para detectar fugas o uso no autorizado","Una tercera válvula de retención principal"], re:"La versión detector agrega una derivación medida alrededor de las retenciones principales para que pequeños flujos (una fuga o un robo) se registren en el medidor, útil en sistemas contra incendios."},
  {id:456, q:"Un conjunto RP instalado al aire libre sobre el nivel del suelo típicamente aún requiere:", opts:["Instalación por debajo de la línea de congelamiento en una fosa sellada","Retirar todos los grifos de prueba","Protección contra congelamiento y espacio libre para que la válvula de alivio descargue libremente","Enterramiento directo en el suelo"], re:"Un RP sobre el nivel del suelo necesita protección contra el congelamiento y un espacio de aire/holgura adecuado en el puerto de alivio para que pueda descargar sin quedar sumergido."},
  {id:457, q:"El Código de Plomería de California está codificado como:", opts:["Título 8 del Código de Regulaciones de California","Título 16, Parte 2 del Código de Regulaciones de California","Título 25, Parte 1 del Código de Regulaciones de California","Título 24, Parte 5 del Código de Regulaciones de California"], re:"El Código de Plomería de California es la Parte 5 del Título 24 (el Código de Normas de Construcción de California) dentro del Código de Regulaciones de California."},
  {id:458, q:"¿En qué código modelo se basa (se adopta) el Código de Plomería de California?", opts:["El Código Internacional de Plomería (IPC)","El Código Nacional Estándar de Plomería","El Código Uniforme de Plomería (UPC) publicado por IAPMO","El Código Internacional de Construcción Residencial (IRC)"], re:"California adopta el Código Uniforme de Plomería (UPC), publicado por IAPMO, con enmiendas estatales, como su Código de Plomería (Título 24, Parte 5)."},
  {id:459, q:"El Título 24 del Código de Regulaciones de California se conoce colectivamente como el:", opts:["Código Laboral de California","Código de Salud y Seguridad de California","Código de Normas de Construcción de California","Código Vehicular de California"], re:"El Título 24 es el Código de Normas de Construcción de California; sus partes incluyen los códigos de Construcción, Plomería, Mecánico, Eléctrico y de Energía, entre otros."},
  {id:460, q:"Cuando una jurisdicción local adopta el Código de Plomería de California, puede:", opts:["Adoptar enmiendas más estrictas según las condiciones climáticas, geológicas o topográficas locales","Eliminar todo el código","Ignorar por completo los mínimos estatales","Aplicar el código de otro estado"], re:"Las agencias locales pueden enmendar el código estatal para hacerlo más restrictivo cuando lo justifiquen las condiciones locales, pero el código estatal fija las normas mínimas de base."},
  {id:461, q:"Según la Ley de Agua Potable Segura y la ley de California, 'libre de plomo' para tuberías, accesorios y artefactos significa un contenido de plomo promedio ponderado de las superficies en contacto que no exceda:", opts:["0,25 por ciento","8,0 por ciento","2,0 por ciento","5,0 por ciento"], re:"'Libre de plomo' es un promedio ponderado de no más del 0,25 por ciento de plomo en las superficies en contacto de tuberías, accesorios y artefactos usados para agua potable."},
  {id:462, q:"Para la soldadura y el fundente usados en tuberías de agua potable, el contenido máximo de plomo 'libre de plomo' es:", opts:["0,25 por ciento","2,0 por ciento","0,2 por ciento","5,0 por ciento"], re:"La soldadura y el fundente para agua potable no deben contener más del 0,2 por ciento de plomo, una cifra más estricta que el promedio ponderado del 0,25 por ciento de las superficies en contacto."},
  {id:463, q:"Los requisitos de 'libre de plomo' para productos de plomería potable se aplican a los componentes que:", opts:["Transportan o dispensan agua para consumo humano (beber o cocinar)","Solo transportan agua caliente","Se usan solo en sistemas de drenaje","Están enterrados bajo nivel únicamente"], re:"Las reglas de libre de plomo cubren productos que transportan o dispensan agua para consumo humano, incluidos los grifos de cocina y baño y otros dispositivos de uso final potable."},
  {id:464, q:"El propósito principal declarado del Código de Plomería de California es proveer requisitos mínimos que protejan:", opts:["La cuota de mercado de los fabricantes","Solo la inversión del propietario del edificio","Las decisiones estéticas de diseño","La salud, seguridad y bienestar públicos"], re:"Como su modelo UPC, el Código de Plomería de California existe para salvaguardar la salud, seguridad y bienestar públicos mediante normas mínimas de plomería."},
  {id:465, q:"¿Qué organismo adopta y publica las normas de construcción de California, incluido el Código de Plomería?", opts:["La Agencia de Protección Ambiental de EE. UU.","La Junta de Licencias de Contratistas del Estado","La Autoridad Federal de Plomería","La Comisión de Normas de Construcción de California"], re:"La Comisión de Normas de Construcción de California adopta y publica el Título 24, coordinando las agencias estatales que proponen las normas de plomería y otras."},
  {id:466, q:"Los materiales y productos usados en una instalación de plomería en California generalmente deben ser:", opts:["Fabricados solo en California","Listados/aprobados según las normas referenciadas y aceptados por la autoridad competente","Los más económicos disponibles","Reciclados de proyectos anteriores"], re:"Los productos deben cumplir las normas referenciadas en el código y ser aceptables para la autoridad competente, asegurando que se usen materiales probados en sistemas potables y de DWV."},
  {id:467, q:"Cuando existe un conflicto entre el Código de Plomería de California y una enmienda local más restrictiva legalmente adoptada, el instalador debe seguir:", opts:["La que sea menos restrictiva","El requisito más restrictivo legalmente adoptado","Solo el catálogo del fabricante","La regla de una jurisdicción vecina"], re:"Cuando una enmienda local legalmente adoptada es más restrictiva, esta rige. El código fija mínimos, y las reglas locales más estrictas prevalecen si se adoptan correctamente."},
  {id:468, q:"El Código de Plomería de California se vuelve a publicar en un ciclo de adopción de aproximadamente cada:", opts:["Año","Diez años","Veinte años","Tres años"], re:"Las normas de construcción de California, incluido el Código de Plomería, se publican generalmente en un ciclo de tres años, con suplementos intermedios según sea necesario."},
  {id:469, q:"Según el código, la 'autoridad competente' (AHJ) se refiere a:", opts:["La casa de suministros de plomería","La agencia o funcionario responsable de hacer cumplir el código y aprobar la instalación","El fabricante de la tubería","El propietario"], re:"La AHJ es el organismo o funcionario que hace cumplir el código (comúnmente el departamento de construcción local) que lo interpreta, emite permisos y aprueba el trabajo."},
  {id:470, q:"Los materiales o métodos alternativos no prescritos específicamente por el código solo pueden usarse si:", opts:["La autoridad competente los aprueba como equivalentes en calidad y seguridad","El contratista los prefiere","Son más baratos que las opciones listadas en el código","Son comunes en otro estado"], re:"El código permite alternativas cuando la autoridad competente los considera equivalentes a los requisitos prescritos en desempeño, seguridad y calidad, no a sola discreción del instalador."},
  {id:471, q:"La tubería de agua potable en California debe protegerse de la contaminación, lo que el código logra principalmente mediante:", opts:["Diámetros de tubería más grandes","Control de conexiones cruzadas y protección de reflujo aprobada","Mayor presión de agua","Artefactos con código de colores"], re:"Las disposiciones de suministro de agua del código exigen control de conexiones cruzadas y prevención de reflujo para mantener el sistema potable libre de contaminación."},
  {id:472, q:"Una marca de certificación reconocida de un tercero en un producto de agua potable indica que:", opts:["Está exento del código","Ha sido probado conforme a normas aplicables de efectos sobre la salud y de desempeño","Fue instalado por un contratista con licencia","Es la opción más barata"], re:"Una marca de certificación muestra que el producto cumplió normas aplicables (incluidas las de contenido de plomo y efectos sobre la salud) y es apto para uso con agua potable."},
  {id:473, q:"Las normas mínimas del Código de Plomería de California representan:", opts:["El máximo que puede instalarse alguna vez","Pautas opcionales sin fuerza de ley","Requisitos solo para construcción nueva","El nivel mínimo aceptable de trabajo; se permite una mejor práctica"], re:"Los requisitos del código son mínimos. Un instalador puede superarlos, pero no puede brindar menos protección que la que el código exige."},
  {id:474, q:"El cumplimiento del Código de Plomería de California es legalmente obligatorio porque el código es:", opts:["Una recomendación voluntaria del oficio","Un documento de garantía del fabricante","Una política interna de la empresa","Adoptado como ley en forma de regulación (Título 24) exigible por las jurisdicciones"], re:"Como regulación estatal adoptada, el Código de Plomería de California tiene fuerza de ley y es exigido por los funcionarios de construcción locales."},
  {id:475, q:"Antes de comenzar la mayoría de las instalaciones de plomería, un contratista primero debe:", opts:["Terminar el trabajo y luego notificar a la ciudad","Obtener un permiso de plomería de la autoridad competente","Programar solo la inspección final","Colocar un aviso en la casa de suministros"], re:"Debe obtenerse un permiso antes de iniciar el trabajo para que la jurisdicción pueda revisar el alcance y programar las inspecciones requeridas en las etapas adecuadas."},
  {id:476, q:"La inspección de plomería en bruto (rough-in) generalmente se realiza:", opts:["Después de instalar las paredes y los acabados","Después de instalar la tubería pero antes de ocultarla o cubrirla","Solo después de que el edificio esté ocupado","Antes de colocar cualquier tubería"], re:"La inspección en bruto ocurre cuando la tubería de DWV, agua y gas está instalada y aún expuesta, para que el inspector pueda verificar el trabajo antes de ocultarlo."},
  {id:477, q:"La prueba de agua en un sistema de DWV requiere que el sistema se llene de agua para dar una carga de al menos:", opts:["5 pies","1 pie","20 pies","10 pies"], re:"La prueba de agua del DWV llena la sección hasta una carga de al menos 10 pies por encima del accesorio más alto de esa sección, y luego la mantiene para verificar fugas."},
  {id:478, q:"Al probar el DWV con aire en lugar de agua, el código generalmente requiere una presión manométrica de al menos:", opts:["5 psi","1 psi","20 psi","50 psi"], re:"Una prueba de aire del sistema de DWV se mantiene a no menos de 5 psi (o 10 pulgadas de columna de mercurio), sostenida sin pérdida durante el período requerido."},
  {id:479, q:"Una prueba de DWV (agua o aire) debe mantenerse sin fugas durante un mínimo de aproximadamente:", opts:["15 minutos","5 segundos","60 minutos","1 minuto"], re:"La prueba de DWV debe mantenerse al menos 15 minutos sin caída, demostrando que la tubería de drenaje y ventilación es hermética antes de ocultarla."},
  {id:480, q:"La tubería de suministro (distribución) de agua se prueba típicamente y se comprueba su hermeticidad con una prueba de presión de aire de aproximadamente:", opts:["50 psi","5 psi","10 psi","200 psi"], re:"La tubería de suministro de agua potable se prueba comúnmente a 50 psi de aire (o a la presión de trabajo del agua) y debe mantenerse sin fugas durante al menos 15 minutos."},
  {id:481, q:"Al probar su hermeticidad, la tubería de distribución de agua debe soportar la prueba sin fugas durante al menos:", opts:["5 minutos","1 hora","15 minutos","24 horas"], re:"Ya sea probada con aire o con la presión de trabajo del agua, la tubería de suministro debe mantenerse no menos de 15 minutos sin fugas."},
  {id:482, q:"La tubería de gas combustible de un sistema común de baja presión suele comprobarse hermética antes de su uso con una prueba de aire o gas inerte de al menos aproximadamente:", opts:["10 psi","1 psi","100 psi","0,5 psi"], re:"La tubería de gas de baja presión se prueba típicamente a no menos de 10 psi y se mantiene durante el tiempo requerido; verifique el valor exacto según la presión de operación del sistema y la edición del código."},
  {id:483, q:"En una prueba que requiere una presión de 10 psi o menos, el código exige un manómetro con incrementos graduados de:", opts:["0,10 psi o menos","1,0 psi o menos","5 psi o menos","10 psi o menos"], re:"Las pruebas de baja presión (10 psi o menos) deben usar un manómetro legible en incrementos de 0,10 psi o más finos para poder detectar pequeñas pérdidas con precisión."},
  {id:484, q:"La inspección final de plomería se realiza:", opts:["Antes de instalar cualquier tubería","Cuando todo el trabajo de plomería y los artefactos están completos y listos para usar","Solo en el sistema de gas","Al mismo tiempo que la inspección en bruto"], re:"La inspección final ocurre después de colocar los artefactos y completar el sistema, verificando que todo funcione correctamente y cumpla el código antes de la ocupación."},
  {id:485, q:"El trabajo que ha sido cubierto u ocultado antes de la inspección requerida generalmente debe:", opts:["Dejarse como está y aprobarse después","Reportarse solo en la inspección final","Descubrirse o ponerse disponible para inspección a indicación del inspector","Ignorarse si el contratista tiene licencia"], re:"Si se omiten las inspecciones requeridas y el trabajo se oculta, la autoridad competente puede exigir que se descubra para poder verificar la instalación."},
  {id:486, q:"¿Quién es responsable de notificar a la autoridad y solicitar las inspecciones requeridas en las etapas adecuadas?", opts:["La empresa de agua","El titular del permiso (contratista) que realiza el trabajo","El fabricante del artefacto","El propietario vecino"], re:"El titular del permiso debe solicitar las inspecciones en cada etapa requerida; el trabajo no puede avanzar más allá de una inspección requerida hasta que sea aprobada."},
  {id:487, q:"Un conjunto de prevención de reflujo recién instalado bajo permiso debe ser:", opts:["Ocultado antes de la inspección","Instalado sin ninguna prueba","Comprobado por un comprobador certificado y los resultados entregados a la autoridad","Aprobado solo verbalmente"], re:"Los conjuntos comprobables recién instalados deben ser probados por un comprobador certificado de reflujo, con los resultados aprobatorios presentados a la autoridad para su aceptación."},
  {id:488, q:"Durante una prueba de tubería requerida, el sistema debe observarse:", opts:["Con presión aplicada solo momentáneamente","Solo después de conectar los artefactos","Para mantener la presión de prueba durante toda la duración requerida sin fugas","Mientras el agua circula activamente por él"], re:"Una prueba de presión válida mantiene la presión especificada durante todo el tiempo requerido sin pérdida medible, confirmando que el sistema no tiene fugas."},
  {id:489, q:"Si una inspección revela una infracción del código, el contratista generalmente debe:", opts:["Ocultar el trabajo rápidamente","Continuar y arreglarlo después de la ocupación","Cambiar a un permiso diferente","Corregir la deficiencia y solicitar una nueva inspección antes de continuar"], re:"Las infracciones identificadas deben corregirse y volver a inspeccionarse; la instalación no puede avanzar legalmente más allá de una inspección reprobada hasta resolver el problema."},
  {id:490, q:"Normalmente se requiere un permiso de plomería para cuál de los siguientes?", opts:["Desobstruir un sifón existente con un destapador","Reemplazar la arandela de un grifo","Instalar nueva tubería de agua, gas o DWV, o reemplazar un calentador de agua","Limpiar el aireador de un artefacto"], re:"La tubería nueva y los trabajos importantes como el reemplazo del calentador de agua requieren permiso; las reparaciones menores y el mantenimiento de rutina generalmente no."},
  {id:491, q:"La clasificación C-36 de Plomería de la CSLB autoriza a un contratista a proveer:", opts:["Un suministro de agua seguro y la eliminación adecuada de desechos fluidos en estructuras y obras fijas","Solo cableado eléctrico","Solo estructura de armazón","Techado y revestimiento"], re:"El alcance del C-36 cubre el suministro de agua seguro y adecuado y la eliminación adecuada de desechos fluidos, el núcleo del trabajo de suministro potable y drenaje."},
  {id:492, q:"¿Cuál de los siguientes está dentro del alcance de un contratista de plomería C-36?", opts:["Instalar calentadores de agua, tubería de gas, preventores de reflujo y sistemas de DWV","Instalar el panel eléctrico principal del edificio","Verter cimientos estructurales","Instalar ductos de HVAC como oficio principal"], re:"El C-36 cubre sistemas de suministro de agua y DWV, tubería y aparatos de gas combustible, calentadores de agua y prevención de reflujo, el trabajo de plomería reconocido del oficio."},
  {id:493, q:"Un contratista de plomería C-36 que realiza un trabajo fuera de la clasificación de plomería debe:", opts:["Tener o subcontratar la clasificación de licencia adecuada para ese trabajo","Proceder sin restricción","Ignorar las licencias para trabajo incidental","Obtener solo un permiso federal"], re:"El trabajo fuera del alcance del C-36 requiere la clasificación adecuada; un contratista no puede ejecutar por sí mismo oficios no relacionados sin la licencia correspondiente."},
  {id:494, q:"Las clasificaciones de contratista de la CSLB, incluida la C-36, se establecen bajo:", opts:["Regulaciones federales de OSHA","El Código Uniforme de Plomería","Título 24, Parte 6","El Código de Regulaciones de California, Título 16 (reglas de la Junta de Licencias de Contratistas del Estado)"], re:"Las clasificaciones de contratista como la C-36 se definen en el Título 16 del Código de Regulaciones de California, el marco regulatorio de la CSLB."},
  {id:495, q:"La instalación por un contratista de plomería C-36 de gas medicinal o válvulas de corte de gas accionadas por sismo está:", opts:["Completamente fuera del alcance del C-36","Reservada exclusivamente a una licencia de ingeniería general (A)","Permitida solo con una licencia eléctrica","Dentro del alcance reconocido de la clasificación de plomería C-36"], re:"El alcance del C-36 incluye trabajos relacionados con la plomería como la tubería de gas medicinal y las válvulas de corte de gas sísmicas, además de los sistemas de agua, DWV y gas combustible."},
  {id:496, q:"Según las reglas de excavación de OSHA, generalmente se requiere un sistema de protección (talud, apuntalamiento o blindaje) para zanjas con una profundidad de:", opts:["2 pies o más","10 pies o más","5 pies o más (a menos que sea roca estable)","20 pies o más"], re:"Las zanjas de 5 pies de profundidad o más requieren un sistema de protección a menos que se excaven enteramente en roca estable, para proteger a los trabajadores de derrumbes."},
  {id:497, q:"Para una excavación de 20 pies o más de profundidad, el sistema de protección debe ser:", opts:["Diseñado por (o basado en datos tabulados aprobados por) un ingeniero profesional registrado","Elegido por cualquier trabajador en el sitio","Omitido porque es demasiado profundo","Reemplazado solo por una señal de advertencia"], re:"Las excavaciones de 20 pies o más requieren un sistema de protección diseñado por un ingeniero profesional registrado (o datos tabulados aprobados por un IP) debido al grave riesgo de derrumbe."},
  {id:498, q:"El material excavado y los escombros deben mantenerse alejados del borde de una zanja por al menos:", opts:["2 pies","6 pulgadas","10 pies","Puede colocarse en el borde"], re:"Las pilas de material excavado y el equipo deben mantenerse a al menos 2 pies del borde de la zanja para que su peso y la caída de material no provoquen un colapso."},
  {id:499, q:"Debe proveerse un medio de salida seguro (escalera, rampa o escalinata) en zanjas de 4 pies o más de profundidad para que los trabajadores recorran no más de:", opts:["10 pies lateralmente para alcanzarlo","25 pies lateralmente para alcanzarlo","50 pies lateralmente para alcanzarlo","100 pies lateralmente para alcanzarlo"], re:"En zanjas de 4 pies o más de profundidad, un medio de salida debe estar dentro de 25 pies de recorrido lateral para cualquier trabajador, permitiendo un escape rápido."},
  {id:500, q:"Antes de excavar, un plomero debe contactar al servicio regional de llamada única (811) para:", opts:["Que las instalaciones subterráneas existentes sean localizadas y marcadas","Pedir materiales de tubería","Programar la inspección final","Obtener un permiso de plomería"], re:"Llamar al 811 antes de excavar hace que se localicen y marquen las instalaciones enterradas, evitando golpes peligrosos y costosos a líneas de gas, electricidad, agua y otras."}
];
